1	package com.reslife.api.domain.user;
2	
3	import com.reslife.api.common.SoftDeletableEntity;
4	import jakarta.persistence.*;
5	import lombok.Getter;
6	import lombok.NoArgsConstructor;
7	import lombok.Setter;
8	import org.hibernate.annotations.SQLRestriction;
9	
10	import java.time.Instant;
11	import java.util.HashSet;
12	import java.util.Set;
13	import java.util.UUID;
14	
15	@Getter
16	@Setter
17	@NoArgsConstructor
18	@Entity
19	@Table(name = "users")
20	@SQLRestriction("deleted_at IS NULL")
21	public class User extends SoftDeletableEntity {
22	
23	    @Column(nullable = false, unique = true, length = 100)
24	    private String username;
25	
26	    @Column(nullable = false, unique = true, length = 255)
27	    private String email;
28	
29	    @Column(name = "password_hash", nullable = false, length = 255)
30	    private String passwordHash;
31	
32	    @Column(name = "first_name", length = 100)
33	    private String firstName;
34	
35	    @Column(name = "last_name", length = 100)
36	    private String lastName;
37	
38	    @Enumerated(EnumType.STRING)
39	    @Column(name = "account_status", nullable = false, length = 20)
40	    private AccountStatus accountStatus = AccountStatus.ACTIVE;
41	
42	    @Column(name = "status_reason", columnDefinition = "TEXT")
43	    private String statusReason;
44	
45	    /** UUID of the admin user who last changed the account status. Stored loose (not FK) to survive admin deletion. */
46	    @Column(name = "status_changed_by")
47	    private UUID statusChangedBy;
48	
49	    @Column(name = "status_changed_at")
50	    private Instant statusChangedAt;
51	
52	    /**
53	     * Set only by the explicit account-deletion workflow.
54	     * A scheduled task hard-deletes the row 30 days after this timestamp.
55	     */
56	    @Column(name = "scheduled_purge_at")
57	    private Instant scheduledPurgeAt;
58	
59	    @OneToMany(mappedBy = "user", cascade = CascadeType.ALL, orphanRemoval = true, fetch = FetchType.LAZY)
60	    private Set<UserRole> userRoles = new HashSet<>();
61	
62	    public boolean isActive() {
63	        return accountStatus == AccountStatus.ACTIVE;
64	    }
65	
66	    public String getFullName() {
67	        return firstName + " " + lastName;
68	    }
69	}
