1	package com.reslife.api.admin;
2	
3	import com.reslife.api.auth.LoginResponse;
4	import com.reslife.api.domain.user.User;
5	import com.reslife.api.security.ReslifeUserDetails;
6	import jakarta.servlet.http.HttpServletRequest;
7	import jakarta.validation.Valid;
8	import org.springframework.http.ResponseEntity;
9	import org.springframework.security.access.prepost.PreAuthorize;
10	import org.springframework.security.core.annotation.AuthenticationPrincipal;
11	import org.springframework.web.bind.annotation.*;
12	
13	import java.util.UUID;
14	
15	@RestController
16	@RequestMapping("/api/admin/users")
17	@PreAuthorize("hasAnyRole('ADMIN', 'HOUSING_ADMINISTRATOR')")
18	public class AdminUserController {
19	
20	    private final AdminUserService adminUserService;
21	
22	    public AdminUserController(AdminUserService adminUserService) {
23	        this.adminUserService = adminUserService;
24	    }
25	
26	    /**
27	     * DELETE /api/admin/users/{id}
28	     *
29	     * <p>Soft-deletes the account and schedules it for permanent purge after a 30-day
30	     * grace period. All active sessions for the target user are invalidated immediately.
31	     */
32	    @DeleteMapping("/{id}")
33	    public ResponseEntity<Void> deleteUser(
34	            @PathVariable UUID id,
35	            @AuthenticationPrincipal ReslifeUserDetails actor,
36	            HttpServletRequest httpRequest) {
37	        adminUserService.deleteAccount(id, actor.getUserId(), httpRequest);
38	        return ResponseEntity.noContent().build();
39	    }
40	
41	    /**
42	     * PATCH /api/admin/users/{id}/status
43	     *
44	     * <p>Allowed status transitions an admin can apply:
45	     * <ul>
46	     *   <li>{@code ACTIVE}      — re-activate a disabled or frozen account</li>
47	     *   <li>{@code DISABLED}    — disable account sign-in without scheduling deletion</li>
48	     *   <li>{@code FROZEN}      — temporarily freeze (no purge clock)</li>
49	     *   <li>{@code BLACKLISTED} — permanent policy violation block</li>
50	     * </ul>
51	     *
52	     * <p>All changes are audit-logged and all active sessions for the target user
53	     * are invalidated immediately.
54	     */
55	    @PatchMapping("/{id}/status")
56	    public ResponseEntity<LoginResponse> updateStatus(
57	            @PathVariable UUID id,
58	            @Valid @RequestBody UpdateStatusRequest request,
59	            @AuthenticationPrincipal ReslifeUserDetails actor,
60	            HttpServletRequest httpRequest) {
61	
62	        User updated = adminUserService.updateAccountStatus(
63	                id, request.status(), request.reason(), actor.getUserId(), httpRequest);
64	
65	        return ResponseEntity.ok(LoginResponse.from(updated));
66	    }
67	}
