1	package com.reslife.api.config;
2	
3	import com.fasterxml.jackson.databind.ObjectMapper;
4	import com.reslife.api.domain.integration.IntegrationAuthFilter;
5	import com.reslife.api.security.AccountStatusFilter;
6	import com.reslife.api.security.UserDetailsServiceImpl;
7	import jakarta.servlet.http.HttpServletResponse;
8	import org.springframework.context.annotation.Bean;
9	import org.springframework.context.annotation.Configuration;
10	import org.springframework.http.MediaType;
11	import org.springframework.security.authentication.AuthenticationManager;
12	import org.springframework.security.authentication.ProviderManager;
13	import org.springframework.security.authentication.dao.DaoAuthenticationProvider;
14	import org.springframework.security.config.annotation.method.configuration.EnableMethodSecurity;
15	import org.springframework.security.config.annotation.web.builders.HttpSecurity;
16	import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
17	import org.springframework.security.config.http.SessionCreationPolicy;
18	import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder;
19	import org.springframework.security.crypto.password.PasswordEncoder;
20	import org.springframework.security.web.SecurityFilterChain;
21	import org.springframework.security.web.authentication.UsernamePasswordAuthenticationFilter;
22	import org.springframework.security.web.context.HttpSessionSecurityContextRepository;
23	import org.springframework.security.web.context.SecurityContextRepository;
24	import org.springframework.security.web.csrf.CookieCsrfTokenRepository;
25	import org.springframework.security.web.csrf.CsrfTokenRequestAttributeHandler;
26	
27	import java.util.Map;
28	
29	@Configuration
30	@EnableWebSecurity
31	@EnableMethodSecurity  // enables @PreAuthorize on admin controllers
32	public class SecurityConfig {
33	
34	    private final UserDetailsServiceImpl userDetailsService;
35	    private final AccountStatusFilter accountStatusFilter;
36	    private final ObjectMapper objectMapper;
37	
38	    public SecurityConfig(UserDetailsServiceImpl userDetailsService,
39	                          AccountStatusFilter accountStatusFilter,
40	                          ObjectMapper objectMapper) {
41	        this.userDetailsService = userDetailsService;
42	        this.accountStatusFilter = accountStatusFilter;
43	        this.objectMapper = objectMapper;
44	    }
45	
46	    @Bean
47	    public SecurityFilterChain filterChain(HttpSecurity http,
48	                                           IntegrationAuthFilter integrationAuthFilter) throws Exception {
49	        http
50	            // CSRF: cookie-based token repository so the React frontend can read the
51	            // XSRF-TOKEN cookie and send it back as X-XSRF-TOKEN on mutating requests.
52	            // CsrfTokenRequestAttributeHandler (not XorCsrf…) keeps the token un-masked
53	            // for simple JSON clients.
54	            // Integration endpoints use HMAC auth and are called by on-prem devices,
55	            // not browsers — CSRF does not apply.
56	            .csrf(csrf -> csrf
57	                .csrfTokenRepository(CookieCsrfTokenRepository.withHttpOnlyFalse())
58	                .csrfTokenRequestHandler(new CsrfTokenRequestAttributeHandler())
59	                .ignoringRequestMatchers("/api/auth/login", "/api/integrations/**")
60	            )
61	            .sessionManagement(sm -> sm
62	                .sessionCreationPolicy(SessionCreationPolicy.IF_REQUIRED)
63	                .maximumSessions(5)
64	            )
65	            // IntegrationAuthFilter runs before the session-based auth filter so it
66	            // can short-circuit invalid HMAC requests before any session is consulted.
67	            .addFilterBefore(integrationAuthFilter, UsernamePasswordAuthenticationFilter.class)
68	            // Per-request account-status check for session-authenticated users
69	            .addFilterAfter(accountStatusFilter, UsernamePasswordAuthenticationFilter.class)
70	            .authorizeHttpRequests(authz -> authz
71	                .requestMatchers("/api/auth/login", "/api/auth/csrf").permitAll()
72	                .requestMatchers("/api/health").permitAll()
73	                // Integration endpoints: Spring Security permits all; HMAC auth is
74	                // enforced by IntegrationAuthFilter before the request reaches the controller.
75	                .requestMatchers("/api/integrations/**").permitAll()
76	                .requestMatchers("/api/admin/**").hasAnyRole("ADMIN", "HOUSING_ADMINISTRATOR")
77	                .anyRequest().authenticated()
78	            )
79	            // Return JSON 401 — never redirect to a login page
80	            .exceptionHandling(ex -> ex
81	                .authenticationEntryPoint((req, res, e) -> {
82	                    res.setStatus(HttpServletResponse.SC_UNAUTHORIZED);
83	                    res.setContentType(MediaType.APPLICATION_JSON_VALUE);
84	                    objectMapper.writeValue(res.getWriter(),
85	                            Map.of("error", "Authentication required"));
86	                })
87	                .accessDeniedHandler((req, res, e) -> {
88	                    res.setStatus(HttpServletResponse.SC_FORBIDDEN);
89	                    res.setContentType(MediaType.APPLICATION_JSON_VALUE);
90	                    objectMapper.writeValue(res.getWriter(),
91	                            Map.of("error", "Access denied"));
92	                })
93	            )
94	            // Disable built-in form login and HTTP Basic — auth is via custom /api/auth/login
95	            .formLogin(form -> form.disable())
96	            .httpBasic(basic -> basic.disable())
97	            .logout(logout -> logout.disable()); // handled by /api/auth/logout endpoint
98	
99	        return http.build();
100	    }
101	
102	    // -----------------------------------------------------------------------
103	    // Authentication infrastructure
104	    // -----------------------------------------------------------------------
105	
106	    /** BCrypt with work factor 12 as required. */
107	    @Bean
108	    public PasswordEncoder passwordEncoder() {
109	        return new BCryptPasswordEncoder(12);
110	    }
111	
112	    /**
113	     * DaoAuthenticationProvider wired to our UserDetailsService and password encoder.
114	     * hideUserNotFoundExceptions=true (the default) converts UsernameNotFoundException
115	     * to BadCredentialsException so callers cannot distinguish "no such user" from
116	     * "wrong password".
117	     */
118	    @Bean
119	    public AuthenticationManager authenticationManager() {
120	        DaoAuthenticationProvider provider = new DaoAuthenticationProvider();
121	        provider.setUserDetailsService(userDetailsService);
122	        provider.setPasswordEncoder(passwordEncoder());
123	        // hideUserNotFoundExceptions defaults to true — keep it that way
124	        return new ProviderManager(provider);
125	    }
126	
127	    /**
128	     * Explicit SecurityContextRepository bean so AuthController can save
129	     * the context to the session without relying on a thread-local side effect.
130	     */
131	    @Bean
132	    public SecurityContextRepository securityContextRepository() {
133	        return new HttpSessionSecurityContextRepository();
134	    }
135	}
