1	package com.reslife.api.security;
2	
3	import com.reslife.api.domain.user.AccountStatus;
4	import com.reslife.api.domain.user.UserRepository;
5	import jakarta.servlet.FilterChain;
6	import jakarta.servlet.ServletException;
7	import jakarta.servlet.http.HttpServletRequest;
8	import jakarta.servlet.http.HttpServletResponse;
9	import jakarta.servlet.http.HttpSession;
10	import org.springframework.security.authentication.AnonymousAuthenticationToken;
11	import org.springframework.security.core.Authentication;
12	import org.springframework.security.core.context.SecurityContextHolder;
13	import org.springframework.stereotype.Component;
14	import org.springframework.web.filter.OncePerRequestFilter;
15	
16	import java.io.IOException;
17	
18	/**
19	 * Per-request filter that re-checks the authenticated user's account status
20	 * against the database. This provides sub-request granularity for admin actions
21	 * like DISABLE or BLACKLIST — the affected user's active session is invalidated
22	 * on their very next request, not just at the next login.
23	 *
24	 * <p>The DB lookup is a PK lookup (~1ms) and is acceptable overhead for a small
25	 * internal portal. For high-throughput APIs a short-TTL cache would be appropriate.
26	 */
27	@Component
28	public class AccountStatusFilter extends OncePerRequestFilter {
29	
30	    private final UserRepository userRepository;
31	
32	    public AccountStatusFilter(UserRepository userRepository) {
33	        this.userRepository = userRepository;
34	    }
35	
36	    @Override
37	    protected void doFilterInternal(HttpServletRequest request,
38	                                    HttpServletResponse response,
39	                                    FilterChain chain) throws ServletException, IOException {
40	        Authentication auth = SecurityContextHolder.getContext().getAuthentication();
41	
42	        if (auth != null && auth.isAuthenticated() && !(auth instanceof AnonymousAuthenticationToken)
43	                && auth.getPrincipal() instanceof ReslifeUserDetails principal) {
44	
45	            boolean blocked = userRepository.findById(principal.getUserId())
46	                    .map(user -> user.getAccountStatus() != AccountStatus.ACTIVE)
47	                    .orElse(true); // user row gone (hard-deleted) → treat as blocked
48	
49	            if (blocked) {
50	                SecurityContextHolder.clearContext();
51	                HttpSession session = request.getSession(false);
52	                if (session != null) {
53	                    session.invalidate();
54	                }
55	                response.setStatus(HttpServletResponse.SC_UNAUTHORIZED);
56	                response.setContentType("application/json");
57	                response.getWriter().write("{\"error\":\"Session is no longer valid\"}");
58	                return; // do NOT continue the filter chain
59	            }
60	        }
61	
62	        chain.doFilter(request, response);
63	    }
64	}
