1	package com.reslife.api.admin;
2	
3	import com.reslife.api.domain.system.AuditLog;
4	import com.reslife.api.domain.system.AuditLogRepository;
5	import com.reslife.api.domain.user.AccountStatus;
6	import com.reslife.api.domain.user.FailedLoginAttemptRepository;
7	import com.reslife.api.domain.user.User;
8	import com.reslife.api.domain.user.UserRepository;
9	import jakarta.persistence.EntityNotFoundException;
10	import jakarta.servlet.http.HttpServletRequest;
11	import org.springframework.scheduling.annotation.Scheduled;
12	import org.springframework.session.FindByIndexNameSessionRepository;
13	import org.springframework.session.Session;
14	import org.springframework.stereotype.Service;
15	import org.springframework.transaction.annotation.Transactional;
16	
17	import java.time.Instant;
18	import java.time.temporal.ChronoUnit;
19	import java.util.Map;
20	import java.util.UUID;
21	
22	@Service
23	@Transactional(readOnly = true)
24	public class AdminUserService {
25	
26	    private final UserRepository userRepository;
27	    private final AuditLogRepository auditLogRepository;
28	    private final FailedLoginAttemptRepository attemptRepository;
29	    private final FindByIndexNameSessionRepository<? extends Session> sessionRepository;
30	
31	    public AdminUserService(UserRepository userRepository,
32	                            AuditLogRepository auditLogRepository,
33	                            FailedLoginAttemptRepository attemptRepository,
34	                            FindByIndexNameSessionRepository<? extends Session> sessionRepository) {
35	        this.userRepository = userRepository;
36	        this.auditLogRepository = auditLogRepository;
37	        this.attemptRepository = attemptRepository;
38	        this.sessionRepository = sessionRepository;
39	    }
40	
41	    // -----------------------------------------------------------------------
42	    // Account status management
43	    // -----------------------------------------------------------------------
44	
45	    /**
46	     * Changes a user's account status.
47	     *
48	     * <p>Rules:
49	     * <ul>
50	     *   <li>An admin cannot change their own account status.</li>
51	     *   <li>Disabling/freeze/blacklist affect sign-in only; they do not schedule purge.</li>
52	     *   <li>Only the explicit delete workflow starts the 30-day purge clock.</li>
53	     *   <li>Any status change immediately kills all active sessions for the target user.</li>
54	     * </ul>
55	     */
56	    @Transactional
57	    public User updateAccountStatus(UUID targetUserId, AccountStatus newStatus, String reason,
58	                                    UUID actorUserId, HttpServletRequest httpRequest) {
59	        if (targetUserId.equals(actorUserId)) {
60	            throw new IllegalArgumentException("Administrators cannot change their own account status.");
61	        }
62	
63	        User target = userRepository.findById(targetUserId)
64	                .orElseThrow(() -> new EntityNotFoundException("User not found: " + targetUserId));
65	        if (target.isDeleted()) {
66	            throw new IllegalArgumentException(
67	                    "Soft-deleted accounts cannot change status; they must be purged or restored through a dedicated workflow.");
68	        }
69	
70	        AccountStatus oldStatus = target.getAccountStatus();
71	
72	        target.setAccountStatus(newStatus);
73	        target.setStatusReason(reason);
74	        target.setStatusChangedBy(actorUserId);
75	        target.setStatusChangedAt(Instant.now());
76	
77	        // Status changes do not schedule deletion. The 30-day purge window is
78	        // started only by deleteAccount(), which also sets deleted_at.
79	        if (newStatus == AccountStatus.ACTIVE && !target.isDeleted()) {
80	            target.setScheduledPurgeAt(null);
81	        }
82	
83	        userRepository.save(target);
84	
85	        // Immediately expire all active sessions for the affected user
86	        invalidateUserSessions(target.getUsername());
87	
88	        // Audit the action
89	        String ip = extractClientIp(httpRequest);
90	        String ua = httpRequest.getHeader("User-Agent");
91	        auditStatusChange(target, oldStatus, newStatus, reason, actorUserId, ip, ua);
92	
93	        return target;
94	    }
95	
96	    // -----------------------------------------------------------------------
97	    // Account deletion
98	    // -----------------------------------------------------------------------
99	
100	    /**
101	     * Soft-deletes a user account and schedules it for permanent purge in 30 days.
102	     *
103	     * <p>Unlike {@link #updateAccountStatus}, this is a one-way operation:
104	     * the account is immediately soft-deleted ({@code deleted_at} set) so the
105	     * nightly purge job can find and permanently remove it when the grace period
106	     * expires. All active sessions are invalidated and the action is audit-logged.
107	     */
108	    @Transactional
109	    public void deleteAccount(UUID targetUserId, UUID actorUserId, HttpServletRequest httpRequest) {
110	        if (targetUserId.equals(actorUserId)) {
111	            throw new IllegalArgumentException("Administrators cannot delete their own account.");
112	        }
113	
114	        User target = userRepository.findById(targetUserId)
115	                .orElseThrow(() -> new EntityNotFoundException("User not found: " + targetUserId));
116	
117	        target.softDelete();
118	        target.setScheduledPurgeAt(Instant.now().plus(30, ChronoUnit.DAYS));
119	        target.setAccountStatus(AccountStatus.DISABLED);
120	        target.setStatusChangedBy(actorUserId);
121	        target.setStatusChangedAt(Instant.now());
122	
123	        userRepository.save(target);
124	
125	        invalidateUserSessions(target.getUsername());
126	
127	        User actor = userRepository.findById(actorUserId).orElse(null);
128	        String ip = extractClientIp(httpRequest);
129	        String ua = httpRequest.getHeader("User-Agent");
130	
131	        AuditLog entry = new AuditLog();
132	        entry.setUser(actor);
133	        snapshotActor(entry, actor);
134	        entry.setAction("ACCOUNT_DELETED");
135	        entry.setEntityType("User");
136	        entry.setEntityId(target.getId());
137	        entry.setNewValues("{\"scheduledPurgeAt\":\"" + target.getScheduledPurgeAt() + "\"}");
138	        entry.setIpAddress(ip);
139	        entry.setUserAgent(ua);
140	        auditLogRepository.save(entry);
141	    }
142	
143	    // -----------------------------------------------------------------------
144	    // Scheduled maintenance
145	    // -----------------------------------------------------------------------
146	
147	    /**
148	     * Hard-deletes accounts whose 30-day grace period has expired.
149	     * Runs daily at 02:00. A deletion is logged as an audit entry before
150	     * the row is removed.
151	     */
152	    @Scheduled(cron = "0 0 2 * * *")
153	    @Transactional
154	    public void purgeExpiredAccounts() {
155	        Instant now = Instant.now();
156	        int purged = userRepository.hardDeletePurgeableUsers(now);
157	        if (purged > 0) {
158	            AuditLog entry = new AuditLog();
159	            entry.setAction("PURGE_SCHEDULED");
160	            entry.setEntityType("User");
161	            entry.setNewValues("{\"purgedCount\":" + purged + "}");
162	            auditLogRepository.save(entry);
163	        }
164	    }
165	
166	    /**
167	     * Removes login attempt records older than 30 days to control table growth.
168	     * Runs daily at 03:00.
169	     */
170	    @Scheduled(cron = "0 0 3 * * *")
171	    @Transactional
172	    public void cleanupLoginAttempts() {
173	        Instant cutoff = Instant.now().minus(30, ChronoUnit.DAYS);
174	        attemptRepository.deleteOlderThan(cutoff);
175	    }
176	
177	    // -----------------------------------------------------------------------
178	    // Helpers
179	    // -----------------------------------------------------------------------
180	
181	    private void invalidateUserSessions(String username) {
182	        try {
183	            Map<String, ? extends Session> sessions =
184	                    sessionRepository.findByPrincipalName(username);
185	            sessions.forEach((id, session) -> sessionRepository.deleteById(id));
186	        } catch (Exception ignored) {
187	            // Session store may be unavailable during tests; swallow silently
188	        }
189	    }
190	
191	    private void auditStatusChange(User target, AccountStatus oldStatus, AccountStatus newStatus,
192	                                   String reason, UUID actorUserId, String ip, String ua) {
193	        User actor = userRepository.findById(actorUserId).orElse(null);
194	
195	        AuditLog entry = new AuditLog();
196	        entry.setUser(actor);
197	        snapshotActor(entry, actor);
198	        entry.setAction("ACCOUNT_STATUS_CHANGE");
199	        entry.setEntityType("User");
200	        entry.setEntityId(target.getId());
201	        entry.setOldValues("{\"accountStatus\":\"" + oldStatus + "\"}");
202	        entry.setNewValues("{\"accountStatus\":\"" + newStatus + "\",\"reason\":\""
203	                + (reason != null ? reason.replace("\"", "\\\"") : "") + "\"}");
204	        entry.setIpAddress(ip);
205	        entry.setUserAgent(ua);
206	        auditLogRepository.save(entry);
207	    }
208	
209	    /**
210	     * Copies the actor's username and email into the audit entry at write time.
211	     * These snapshot columns survive even after the actor's user row is hard-purged
212	     * (the {@code user_id} FK becomes NULL; the text values remain).
213	     */
214	    private void snapshotActor(AuditLog entry, User actor) {
215	        if (actor != null) {
216	            entry.setActorUsername(actor.getUsername());
217	            entry.setActorEmail(actor.getEmail());
218	        }
219	    }
220	
221	    private String extractClientIp(HttpServletRequest request) {
222	        String forwarded = request.getHeader("X-Forwarded-For");
223	        if (forwarded != null && !forwarded.isBlank()) {
224	            return forwarded.split(",")[0].strip();
225	        }
226	        return request.getRemoteAddr();
227	    }
228	}
