9	import java.time.Instant;
10	import java.util.List;
11	import java.util.Optional;
12	import java.util.Set;
13	import java.util.UUID;
14	
15	public interface UserRepository extends JpaRepository<User, UUID> {
16	
17	    Optional<User> findByEmail(String email);
18	    Optional<User> findByEmailIgnoreCase(String email);
19	    Optional<User> findByUsername(String username);
20	    Optional<User> findByUsernameIgnoreCase(String username);
21	
22	    boolean existsByEmail(String email);
23	    boolean existsByUsername(String username);
24	
25	    @Query("SELECT u FROM User u JOIN u.userRoles ur JOIN ur.role r WHERE r.name = :roleName")
26	    List<User> findAllByRoleName(RoleName roleName);
27	
28	    /** Search users by name/username for the new-thread user picker. */
29	    @Query("SELECT u FROM User u WHERE u.id != :excludeId AND (" +
30	           "LOWER(u.firstName) LIKE LOWER(CONCAT('%', :q, '%')) OR " +
31	           "LOWER(u.lastName)  LIKE LOWER(CONCAT('%', :q, '%')) OR " +
32	           "LOWER(u.username)  LIKE LOWER(CONCAT('%', :q, '%')))")
33	    List<User> searchUsers(@Param("q") String q, @Param("excludeId") UUID excludeId, Pageable pageable);
34	
35	    @Query("SELECT DISTINCT u FROM User u JOIN u.userRoles ur JOIN ur.role r " +
36	           "WHERE u.id != :excludeId AND r.name IN :roleNames AND (" +
37	           "LOWER(u.firstName) LIKE LOWER(CONCAT('%', :q, '%')) OR " +
38	           "LOWER(u.lastName)  LIKE LOWER(CONCAT('%', :q, '%')) OR " +
39	           "LOWER(u.username)  LIKE LOWER(CONCAT('%', :q, '%')))")
