42	                                      @Param("roleNames") Set<RoleName> roleNames,
43	                                      Pageable pageable);
44	
45	    // -----------------------------------------------------------------------
46	    // Queries that bypass @SQLRestriction("deleted_at IS NULL")
47	    // Required for purge scheduling and admin operations on soft-deleted rows.
48	    // -----------------------------------------------------------------------
49	
50	    /**
51	     * Find users whose soft-delete grace period has expired and are ready for hard deletion.
52	     * Must use nativeQuery to bypass the @SQLRestriction on User.
53	     */
54	    @Query(value = "SELECT * FROM users WHERE deleted_at IS NOT NULL AND scheduled_purge_at <= :now",
