32	/**
33	 * Redirects unauthenticated users to /login.
34	 * Renders a blank screen while the auth state is being resolved
35	 * (avoids a flash of the login page on refresh).
36	 */
37	function RequireAuth({ children }) {
38	  const { user, loading } = useAuth();
39	  if (loading) return null;
