52	/**
53	 * Multipart file upload helper.
54	 * Does NOT set Content-Type — the browser sets it automatically with the
55	 * correct boundary when the body is a FormData instance.
56	 */
57	async function uploadFile(path, formData) {
58	  const res = await fetch(path, {
59	    method: 'POST',
60	    credentials: 'include',
61	    headers: { [CSRF_HEADER]: getCsrfToken() },
62	    body: formData,
63	  });
64	
65	  if (res.status === 204) return null;
66	  const data = await res.json().catch(() => ({}));
67	  if (!res.ok) throw new HttpError(res.status, data);
68	  return data;
69	}
