8	async function api(method, path, body) {
9	  try {
10	    switch (method) {
11	      case 'GET':
12	        return await client.get(path);
13	      case 'POST':
14	        return await client.post(path, body);
15	      case 'PUT':
16	        return await client.put(path, body);
17	      case 'DELETE':
18	        return await client.delete(path);
19	      default:
20	        throw new Error(`Unsupported method: ${method}`);
21	    }
22	  } catch (err) {
23	    if (err?.message) {
24	      throw err;
25	    }
26	    throw new Error('Request failed');
27	  }
28	}
