528	        <div style={{ textAlign: 'center', padding: '3rem', color: '#888', border: '1px dashed #ccc', borderRadius: 6 }}>
529	          No integration keys yet. Create one to get started.
530	        </div>
531	      ) : (
532	        <>
533	          <table style={m.table}>
534	            <thead>
535	              <tr>
536	                {['Name / Key ID', 'Key ID', 'Secret prefix', 'Status', 'Created by', 'Last used', ''].map(h => (
537	                  <th key={h} style={m.th}>{h}</th>
