9	/**
10	 * Extends BaseEntity with a deletedAt field for soft-delete support.
11	 * Each concrete entity must also carry @SQLRestriction("deleted_at IS NULL")
12	 * so that Hibernate automatically excludes deleted rows from queries.
13	 */
14	@Getter
15	@MappedSuperclass
16	public abstract class SoftDeletableEntity extends BaseEntity {
17	
18	    @Column(name = "deleted_at")
19	    private Instant deletedAt;
20	
21	    public boolean isDeleted() {
22	        return deletedAt != null;
23	    }
