28	@Service
29	@Transactional(readOnly = true)
30	public class AdminUserService {
31	
32	    @PersistenceContext
33	    private EntityManager em;
34	
35	    private final UserRepository userRepository;
36	    private final AuditLogRepository auditLogRepository;
37	    private final FailedLoginAttemptRepository attemptRepository;
38	    private final FindByIndexNameSessionRepository<? extends Session> sessionRepository;
39	
40	    public AdminUserService(UserRepository userRepository,
41	                            AuditLogRepository auditLogRepository,
42	                            FailedLoginAttemptRepository attemptRepository,
43	                            FindByIndexNameSessionRepository<? extends Session> sessionRepository) {
44	        this.userRepository = userRepository;
45	        this.auditLogRepository = auditLogRepository;
46	        this.attemptRepository = attemptRepository;
47	        this.sessionRepository = sessionRepository;
48	    }
49	
50	    // -----------------------------------------------------------------------
51	    // User listing / search
52	    // -----------------------------------------------------------------------
53	
54	    /**
55	     * Paginated, searchable list of users for the admin governance screen.
56	     *
57	     * <p>Uses a native query so that soft-deleted accounts (those with
58	     * {@code deleted_at IS NOT NULL}) can be optionally included; the
59	     * {@code @SQLRestriction} on {@link User} would otherwise exclude them
60	     * from every JPQL query.
61	     *
62	     * @param rawQ          free-text search across username, email, first/last name
63	     * @param statusFilter  optional exact-match filter on {@code account_status}
64	     * @param includeDeleted when {@code true}, soft-deleted rows are included
65	     * @param page          zero-based page index
66	     * @param size          page size (callers should cap this, e.g. at 100)
67	     */
68	    public Page<UserSummaryDto> listUsers(String rawQ, AccountStatus statusFilter,
69	                                          boolean includeDeleted, int page, int size) {
70	        String q = rawQ == null ? "" : rawQ.strip();
71	        boolean hasQ = !q.isEmpty();
72	        String likeParam = "%" + q.toLowerCase() + "%";
73	
74	        // Build WHERE clause dynamically to avoid null-parameter binding issues
75	        // in native queries (some JDBC drivers reject typed-null params).
76	        StringBuilder where = new StringBuilder("1=1");
77	        if (hasQ) {
78	            where.append(" AND (LOWER(username) LIKE :like OR LOWER(email) LIKE :like" +
79	                         " OR LOWER(first_name) LIKE :like OR LOWER(last_name) LIKE :like)");
80	        }
81	        if (statusFilter != null) {
82	            where.append(" AND account_status = :status");
83	        }
84	        if (!includeDeleted) {
85	            where.append(" AND deleted_at IS NULL");
86	        }
87	        String w = where.toString();
88	
89	        // Count
90	        jakarta.persistence.Query countQ =
91	                em.createNativeQuery("SELECT COUNT(*) FROM users WHERE " + w);
92	        if (hasQ)             countQ.setParameter("like", likeParam);
93	        if (statusFilter != null) countQ.setParameter("status", statusFilter.name());
94	        long total = ((Number) countQ.getSingleResult()).longValue();
95	
96	        // Data — native query bypasses @SQLRestriction, allowing soft-deleted rows
97	        jakarta.persistence.Query dataQ = em.createNativeQuery(
98	                "SELECT * FROM users WHERE " + w + " ORDER BY created_at DESC", User.class);
99	        if (hasQ)             dataQ.setParameter("like", likeParam);
100	        if (statusFilter != null) dataQ.setParameter("status", statusFilter.name());
101	        dataQ.setFirstResult(page * size);
102	        dataQ.setMaxResults(size);
103	
104	        @SuppressWarnings("unchecked")
105	        List<User> results = (List<User>) dataQ.getResultList();
106	
107	        List<UserSummaryDto> content = results.stream().map(UserSummaryDto::from).toList();
108	        return new PageImpl<>(content, PageRequest.of(page, size), total);
109	    }
