1	package com.reslife.api.domain.crawler;
2	
3	import com.fasterxml.jackson.annotation.JsonIgnoreProperties;
4	
5	import java.util.ArrayList;
6	import java.util.List;
7	
8	/**
9	 * Per-source crawl configuration, stored as JSON in {@code crawl_sources.crawl_config}.
10	 *
11	 * <p>Controls pagination discovery, link following, URL filtering, and item extraction.
12	 * All fields have safe defaults so an empty JSON object produces a working configuration.
13	 */
14	@JsonIgnoreProperties(ignoreUnknown = true)
15	public class CrawlConfig {
16	
17	    // ── Link discovery ─────────────────────────────────────────────────────
18	
19	    /**
20	     * Whether to follow discovered {@code href} links within the allowed depth.
21	     * Set to {@code false} to crawl only the exact {@code baseUrl}.
22	     */
23	    private boolean followLinks = true;
24	
25	    /**
26	     * Regex patterns against which discovered URLs are tested.
27	     * A URL must match at least one pattern to be queued (if non-empty).
28	     * Example: {@code ["^http://intranet\\.local/residents/.*"]}
29	     */
30	    private List<String> allowedPathPatterns = new ArrayList<>();
31	
32	    /**
33	     * Regex patterns for URLs that should never be queued regardless of allow list.
34	     */
35	    private List<String> blockedPathPatterns = new ArrayList<>();
36	
37	    // ── Pagination ─────────────────────────────────────────────────────────
38	
39	    /**
40	     * Regex applied to hrefs to identify "next page" links, e.g. {@code ".*[?&]page=\\d+"}.
41	     * When present, the crawler treats matching links as pagination rather than depth links.
42	     */
43	    private String nextPageUrlPattern;
44	
45	    // ── Item extraction (HTML) ─────────────────────────────────────────────
46	
47	    /**
48	     * CSS selector or XPath identifying individual data items on the page.
49	     * When set, matched elements are serialized and saved as {@code CrawlItem} rows.
50	     * Leave blank to save the full page body as a single item.
51	     */
52	    private String itemSelector;
53	
54	    /**
55	     * JSON pointer / CSS selector to extract a title field from each item.
56	     */
57	    private String titleSelector;
58	
59	    /**
60	     * JSON pointer / CSS selector to extract a canonical URL from each item.
61	     */
62	    private String linkSelector;
63	
64	    // ── Keyword filtering ──────────────────────────────────────────────────
65	
66	    /**
67	     * Only save items whose text content contains at least one of these keywords.
68	     * Empty list = save all items.
69	     */
70	    private List<String> keywords = new ArrayList<>();
71	
72	    // ── Getters / Setters ──────────────────────────────────────────────────
73	
74	    public boolean isFollowLinks() { return followLinks; }
75	    public void setFollowLinks(boolean followLinks) { this.followLinks = followLinks; }
76	
77	    public List<String> getAllowedPathPatterns() { return allowedPathPatterns; }
78	    public void setAllowedPathPatterns(List<String> allowedPathPatterns) { this.allowedPathPatterns = allowedPathPatterns; }
79	
80	    public List<String> getBlockedPathPatterns() { return blockedPathPatterns; }
81	    public void setBlockedPathPatterns(List<String> blockedPathPatterns) { this.blockedPathPatterns = blockedPathPatterns; }
82	
83	    public String getNextPageUrlPattern() { return nextPageUrlPattern; }
84	    public void setNextPageUrlPattern(String nextPageUrlPattern) { this.nextPageUrlPattern = nextPageUrlPattern; }
85	
86	    public String getItemSelector() { return itemSelector; }
87	    public void setItemSelector(String itemSelector) { this.itemSelector = itemSelector; }
88	
89	    public String getTitleSelector() { return titleSelector; }
90	    public void setTitleSelector(String titleSelector) { this.titleSelector = titleSelector; }
91	
92	    public String getLinkSelector() { return linkSelector; }
93	    public void setLinkSelector(String linkSelector) { this.linkSelector = linkSelector; }
94	
95	    public List<String> getKeywords() { return keywords; }
96	    public void setKeywords(List<String> keywords) { this.keywords = keywords; }
97	}
