67	    private int delayMsBetweenRequests = 1_000;
68	
69	    @Column(name = "max_depth", nullable = false)
70	    private int maxDepth = 3;
71	
72	    @Column(name = "max_pages", nullable = false)
73	    private int maxPages = 100;
74	
75	    @Column(name = "is_active", nullable = false)
76	    private boolean active = true;
77	
78	    @Column(name = "last_crawled_at")
