1	package com.reslife.api.domain.crawler;
2	
3	import com.fasterxml.jackson.databind.ObjectMapper;
4	import jakarta.annotation.PreDestroy;
5	import org.slf4j.Logger;
6	import org.slf4j.LoggerFactory;
7	import org.springframework.stereotype.Service;
8	
9	import java.util.List;
10	import java.util.Optional;
11	import java.util.UUID;
12	import java.util.concurrent.ConcurrentHashMap;
13	import java.util.concurrent.ExecutorService;
14	import java.util.concurrent.Executors;
15	import java.util.concurrent.Semaphore;
16	import java.util.concurrent.TimeUnit;
17	
18	/**
19	 * Central execution engine for crawl jobs.
20	 *
21	 * <h3>Concurrency model</h3>
22	 * <p>A {@link Semaphore} with {@link CrawlerProperties#getMaxConcurrent()} permits
23	 * limits the number of jobs that actively fetch pages at the same time (default 5).
24	 * Jobs are submitted to a virtual-thread executor, so they queue cheaply until a
25	 * semaphore permit is available rather than blocking an OS thread.
26	 *
27	 * <h3>Pause / Cancel</h3>
28	 * <p>Each running job is represented by a {@link CrawlJobExecution} entry in
29	 * {@link #activeExecutions}.  Calling {@link #pauseJob} or {@link #cancelJob}
30	 * sets an atomic flag on the execution; the crawl loop checks this flag at the
31	 * start of every iteration (not mid-fetch) to ensure the DB is left consistent.
32	 *
33	 * <h3>Resource protection</h3>
34	 * <ul>
35	 *   <li>Virtual threads are used so thousands of queued jobs don't exhaust OS threads.</li>
36	 *   <li>The semaphore caps actual concurrent network activity.</li>
37	 *   <li>Target URLs are validated as local-network before any request is made
38	 *       (enforced in {@link CrawlFetcherService}).</li>
39	 *   <li>{@link PreDestroy} drains the executor gracefully on shutdown.</li>
40	 * </ul>
41	 */
42	@Service
43	public class CrawlEngineService {
44	
45	    private static final Logger log = LoggerFactory.getLogger(CrawlEngineService.class);
46	
47	    private final Semaphore                              semaphore;
48	    private final ExecutorService                        executor;
49	    private final ConcurrentHashMap<UUID, CrawlJobExecution> activeExecutions = new ConcurrentHashMap<>();
50	
51	    private final CrawlJobRepository    jobRepo;
52	    private final CrawlPageRepository   pageRepo;
53	    private final CrawlItemRepository   itemRepo;
54	    private final CrawlSourceRepository sourceRepo;
55	    private final CrawlFetcherService   fetcher;
56	    private final ObjectMapper          objectMapper;
57	    private final int                   checkpointInterval;
58	    private final int                   maxConcurrent;
59	
60	    public CrawlEngineService(CrawlJobRepository jobRepo,
61	                               CrawlPageRepository pageRepo,
62	                               CrawlItemRepository itemRepo,
63	                               CrawlSourceRepository sourceRepo,
64	                               CrawlFetcherService fetcher,
65	                               ObjectMapper objectMapper,
66	                               CrawlerProperties props) {
67	        this.jobRepo            = jobRepo;
68	        this.pageRepo           = pageRepo;
69	        this.itemRepo           = itemRepo;
70	        this.sourceRepo         = sourceRepo;
71	        this.fetcher            = fetcher;
72	        this.objectMapper       = objectMapper;
73	        this.checkpointInterval = props.getCheckpointIntervalPages();
74	        this.maxConcurrent      = props.getMaxConcurrent();
75	        this.semaphore          = new Semaphore(maxConcurrent, true); // fair ordering
76	        this.executor           = Executors.newVirtualThreadPerTaskExecutor();
77	        log.info("Crawl engine initialised (maxConcurrent={})", maxConcurrent);
78	    }
79	
80	    // ── Submit ─────────────────────────────────────────────────────────────
81	
82	    /**
83	     * Submits a job for execution.  Returns immediately; the job will start
84	     * as soon as a semaphore permit is available.
85	     *
86	     * @throws IllegalStateException if the job is already actively running
87	     */
88	    public void submit(UUID jobId) {
89	        if (activeExecutions.containsKey(jobId)) {
90	            throw new IllegalStateException("Job " + jobId + " is already queued or running");
91	        }
92	
93	        CrawlJob job = jobRepo.findById(jobId)
94	                .orElseThrow(() -> new jakarta.persistence.EntityNotFoundException("CrawlJob not found: " + jobId));
95	
96	        CrawlConfig config = parseConfig(job.getSource());
97	
98	        CrawlJobExecution exec = new CrawlJobExecution(
99	                jobId, job.getSource(), config,
100	                jobRepo, pageRepo, itemRepo, sourceRepo,
101	                fetcher, objectMapper, checkpointInterval);
102	
103	        activeExecutions.put(jobId, exec);
104	
105	        executor.submit(() -> {
106	            boolean acquired = false;
107	            try {
108	                semaphore.acquire();          // blocks until a slot is free
109	                acquired = true;
110	                exec.run();
111	            } catch (InterruptedException e) {
112	                Thread.currentThread().interrupt();
113	                log.warn("Job {} worker thread interrupted while waiting for semaphore", jobId);
114	            } finally {
115	                if (acquired) semaphore.release();
116	                activeExecutions.remove(jobId);
117	            }
118	        });
119	
120	        log.info("Job {} submitted (queue depth ≈ {}, active {}/{})",
121	                jobId, activeExecutions.size(), maxConcurrent - semaphore.availablePermits(), maxConcurrent);
122	    }
123	
124	    // ── Control ────────────────────────────────────────────────────────────
125	
126	    /**
127	     * Signals a running job to pause at the next safe checkpoint.
128	     *
129	     * @return {@code true} if the signal was delivered; {@code false} if the job
130	     *         is not currently running in this engine instance
131	     */
132	    public boolean pauseJob(UUID jobId) {
133	        CrawlJobExecution exec = activeExecutions.get(jobId);
134	        if (exec == null) return false;
135	        exec.requestPause();
136	        log.info("Pause requested for job {}", jobId);
137	        return true;
138	    }
139	
140	    /**
141	     * Signals a running job to stop immediately (after the current fetch completes).
142	     *
143	     * @return {@code true} if the signal was delivered
144	     */
145	    public boolean cancelJob(UUID jobId) {
146	        CrawlJobExecution exec = activeExecutions.get(jobId);
147	        if (exec == null) return false;
148	        exec.requestCancel();
149	        log.info("Cancel requested for job {}", jobId);
150	        return true;
151	    }
152	
153	    // ── Status ─────────────────────────────────────────────────────────────
154	
155	    /** Returns a snapshot of the engine's current operational state. */
156	    public EngineStatus currentStatus() {
157	        int active  = maxConcurrent - semaphore.availablePermits();
158	        return new EngineStatus(maxConcurrent, active, List.copyOf(activeExecutions.keySet()));
159	    }
160	
161	    public record EngineStatus(int maxConcurrent, int activeWorkers, List<UUID> runningJobIds) {}
162	
163	    // ── Lifecycle ──────────────────────────────────────────────────────────
164	
165	    @PreDestroy
166	    void shutdown() {
167	        log.info("Crawl engine shutting down — signalling {} active jobs to cancel", activeExecutions.size());
168	        activeExecutions.values().forEach(CrawlJobExecution::requestCancel);
169	        executor.shutdown();
170	        try {
171	            if (!executor.awaitTermination(30, TimeUnit.SECONDS)) {
172	                executor.shutdownNow();
173	            }
174	        } catch (InterruptedException e) {
175	            executor.shutdownNow();
176	            Thread.currentThread().interrupt();
177	        }
178	    }
179	
180	    // ── Helpers ────────────────────────────────────────────────────────────
181	
182	    private CrawlConfig parseConfig(CrawlSource source) {
183	        String json = source.getCrawlConfig();
184	        if (json == null || json.isBlank()) return new CrawlConfig();
185	        try {
186	            return objectMapper.readValue(json, CrawlConfig.class);
187	        } catch (Exception e) {
188	            log.warn("Source {} has invalid crawlConfig JSON — using defaults: {}", source.getId(), e.getMessage());
189	            return new CrawlConfig();
190	        }
191	    }
192	}
193

1	package com.reslife.api.domain.crawler;
2	
3	import com.reslife.api.domain.integration.LocalNetworkValidator;
4	import org.slf4j.Logger;
5	import org.slf4j.LoggerFactory;
6	import org.springframework.stereotype.Service;
7	
8	import java.net.URI;
9	import java.net.http.HttpClient;
10	import java.net.http.HttpRequest;
11	import java.net.http.HttpResponse;
12	import java.nio.charset.StandardCharsets;
13	import java.security.MessageDigest;
14	import java.security.NoSuchAlgorithmException;
15	import java.time.Duration;
16	import java.util.HexFormat;
17	
18	/**
19	 * Stateless HTTP fetch service for the crawler engine.
20	 *
21	 * <p>All targets are validated against the local-network allowlist before any
22	 * request is made, preventing the crawler from reaching public internet hosts.
23	 *
24	 * <p>Throttle enforcement (delay between requests) is handled by the caller
25	 * ({@link CrawlJobExecution}) because it is stateful per execution.
26	 */
27	@Service
28	public class CrawlFetcherService {
29	
30	    private static final Logger log = LoggerFactory.getLogger(CrawlFetcherService.class);
31	
32	    private final LocalNetworkValidator localNetworkValidator;
33	    private final HttpClient            httpClient;
34	    private final String                userAgent;
35	
36	    public CrawlFetcherService(LocalNetworkValidator localNetworkValidator,
37	                                CrawlerProperties props) {
38	        this.localNetworkValidator = localNetworkValidator;
39	        this.userAgent = props.getUserAgent();
40	        this.httpClient = HttpClient.newBuilder()
41	                .connectTimeout(Duration.ofSeconds(props.getFetchTimeoutSeconds()))
42	                .followRedirects(HttpClient.Redirect.NORMAL)
43	                .build();
44	    }
45	
46	    /**
47	     * Fetches {@code url}, validates it is on the local network, and returns the result.
48	     * Never throws — network/parse errors are returned as {@link FetchResult#networkError}.
49	     */
50	    public FetchResult fetch(String url) {
51	        try {
52	            localNetworkValidator.requireLocalTarget(url);
53	        } catch (IllegalArgumentException e) {
54	            log.warn("Crawler blocked non-local URL {}: {}", url, e.getMessage());
55	            return FetchResult.networkError(url, "Blocked: " + e.getMessage());
56	        }
57	
58	        try {
59	            HttpRequest request = HttpRequest.newBuilder()
60	                    .uri(URI.create(url))
61	                    .header("User-Agent", userAgent)
62	                    .header("Accept", "text/html,application/xhtml+xml,application/json,*/*")
63	                    .timeout(Duration.ofSeconds(30))
64	                    .GET()
65	                    .build();
66	
67	            HttpResponse<String> response = httpClient.send(
68	                    request, HttpResponse.BodyHandlers.ofString(StandardCharsets.UTF_8));
69	
70	            String body = response.body();
71	            int status  = response.statusCode();
72	
73	            if (status < 200 || status >= 400) {
74	                return FetchResult.error(url, status, "HTTP " + status);
75	            }
76	
77	            String hash = sha256(body == null ? "" : body);
78	            return FetchResult.ok(url, status, body, hash);
79	
80	        } catch (InterruptedException e) {
81	            Thread.currentThread().interrupt();
82	            return FetchResult.networkError(url, "Interrupted");
83	        } catch (Exception e) {
84	            log.debug("Fetch error for {}: {}", url, e.getMessage());
85	            return FetchResult.networkError(url, e.getMessage());
86	        }
87	    }
88	
89	    /** Computes the SHA-256 hex digest of the given string (UTF-8 encoded). */
90	    public static String sha256(String input) {
91	        try {
92	            MessageDigest md = MessageDigest.getInstance("SHA-256");
93	            byte[] digest = md.digest(input.getBytes(StandardCharsets.UTF_8));
94	            return HexFormat.of().formatHex(digest);
95	        } catch (NoSuchAlgorithmException e) {
96	            throw new IllegalStateException("SHA-256 not available", e);
97	        }
98	    }
99	}
