68	                      CrawlItemRepository itemRepo, CrawlSourceRepository sourceRepo,
69	                      CrawlFetcherService fetcher,
70	                      ObjectMapper objectMapper, int checkpointInterval) {
71	        this.jobId              = jobId;
72	        this.source             = source;
73	        this.config             = config;
74	        this.jobRepo            = jobRepo;
75	        this.pageRepo           = pageRepo;
76	        this.itemRepo           = itemRepo;
77	        this.sourceRepo         = sourceRepo;
78	        this.fetcher            = fetcher;
79	        this.objectMapper       = objectMapper;
80	        this.checkpointInterval = checkpointInterval;
81	    }
