86	    // ── Main run ───────────────────────────────────────────────────────────
87	
88	    @Override
89	    public void run() {
90	        log.info("Job {} starting — source '{}' ({})", jobId, source.getName(), source.getBaseUrl());
91	        try {
92	            markStatus(CrawlStatus.RUNNING, null);
93	            setStartedAt();
94	
95	            Deque<CrawlCheckpoint.PendingTarget> queue  = loadQueue();
96	            Set<String>                          visited = loadVisitedHashes();
97	
98	            crawlLoop(queue, visited);
99	
100	        } catch (InterruptedException e) {
101	            Thread.currentThread().interrupt();
102	            markStatus(CrawlStatus.FAILED, "Worker thread interrupted");
103	        } catch (Exception e) {
104	            log.error("Job {} failed: {}", jobId, e.getMessage(), e);
105	            markStatus(CrawlStatus.FAILED, truncate(e.getMessage(), 1000));
106	        }
107	    }
