109	    // ── Crawl loop ─────────────────────────────────────────────────────────
110	
111	    private void crawlLoop(Deque<CrawlCheckpoint.PendingTarget> queue,
112	                           Set<String> visited) throws InterruptedException {
113	        int count = 0;
114	
115	        while (!queue.isEmpty()) {
116	            if (cancelRequested.get()) {
117	                saveCheckpoint(queue);
118	                markStatus(CrawlStatus.CANCELLED, null);
119	                return;
120	            }
121	            if (pauseRequested.get()) {
122	                saveCheckpoint(queue);
123	                markStatus(CrawlStatus.PAUSED, null);
124	                return;
125	            }
126	
127	            CrawlCheckpoint.PendingTarget target = queue.poll();
128	            String urlHash = CrawlFetcherService.sha256(target.getUrl());
129	
130	            if (visited.contains(urlHash)) continue;
131	            visited.add(urlHash);
132	
133	            // Per-source throttle
134	            enforceThrottle();
135	
136	            // Fetch
137	            FetchResult result = fetcher.fetch(target.getUrl());
138	            count++;
139	
140	            processResult(target, urlHash, result, queue, visited);
141	
142	            // Periodic checkpoint
143	            if (count % checkpointInterval == 0) saveCheckpoint(queue);
144	
145	            // Respect max-pages limit
146	            if (count >= source.getMaxPages()) {
147	                log.info("Job {} reached max-pages limit ({})", jobId, source.getMaxPages());
148	                break;
149	            }
150	        }
151	
152	        saveCheckpoint(new ArrayDeque<>());
153	        markStatus(CrawlStatus.COMPLETED, null);
154	        updateSourceLastCrawled();
155	        log.info("Job {} completed — {} pages processed", jobId, count);
156	    }
