160	    private void processResult(CrawlCheckpoint.PendingTarget target,
161	                                String urlHash, FetchResult result,
162	                                Deque<CrawlCheckpoint.PendingTarget> queue,
163	                                Set<String> visited) {
164	
165	        UUID pageId = insertPendingPage(target.getUrl(), urlHash, target.getDepth());
166	
167	        if (!result.success()) {
168	            pageRepo.updateFetchResult(pageId, PageStatus.ERROR.name(),
169	                    result.httpStatus(), null, null, truncate(result.errorMessage(), 500));
170	            jobRepo.incrementPagesFailed(jobId);
171	            return;
172	        }
173	
174	        // Incremental update check — skip if content hash unchanged since last crawl
175	        if (contentUnchanged(target.getUrl(), result.contentHash())) {
176	            pageRepo.updateFetchResult(pageId, PageStatus.SKIPPED.name(),
177	                    result.httpStatus(), result.contentHash(),
178	                    result.contentLength(), null);
179	            jobRepo.incrementPagesSkipped(jobId);
180	            return;
181	        }
182	
183	        pageRepo.updateFetchResult(pageId, PageStatus.FETCHED.name(),
184	                result.httpStatus(), result.contentHash(),
185	                result.contentLength(), null);
186	        jobRepo.incrementPagesCrawled(jobId);
187	
188	        extractAndSaveItems(pageId, result);
189	        discoverLinks(result, target.getDepth(), queue, visited);
190	    }
