233	    // ── Link discovery ─────────────────────────────────────────────────────
234	
235	    private void discoverLinks(FetchResult result, int currentDepth,
236	                                Deque<CrawlCheckpoint.PendingTarget> queue,
237	                                Set<String> visited) {
238	
239	        if (!config.isFollowLinks() || result.body() == null) return;
240	        if (currentDepth >= source.getMaxDepth()) return;
241	
242	        List<String> links = extractHrefs(result.body(), result.url());
243	        int nextDepth = currentDepth + 1;
244	
245	        for (String link : links) {
246	            String hash = CrawlFetcherService.sha256(link);
247	            if (visited.contains(hash)) continue;
248	            if (!isAllowed(link)) continue;
249	            queue.offer(new CrawlCheckpoint.PendingTarget(link, nextDepth));
250	        }
251	    }
252	
253	    private List<String> extractHrefs(String body, String baseUrl) {
254	        List<String> result = new ArrayList<>();
255	        Matcher m = HREF.matcher(body);
256	        while (m.find()) {
257	            try {
258	                String href = m.group(1).trim();
259	                if (href.startsWith("javascript:") || href.startsWith("mailto:")) continue;
260	                URI resolved = URI.create(baseUrl).resolve(href);
261	                String url = resolved.toASCIIString();
262	                // Strip fragment
263	                int frag = url.indexOf('#');
264	                if (frag > 0) url = url.substring(0, frag);
265	                result.add(url);
266	            } catch (Exception ignored) {}
267	        }
268	        return result.stream().distinct().toList();
269	    }
270	
271	    private boolean isAllowed(String url) {
272	        List<String> blocked = config.getBlockedPathPatterns();
273	        if (!blocked.isEmpty() && blocked.stream().anyMatch(url::matches)) return false;
274	        List<String> allowed = config.getAllowedPathPatterns();
275	        if (!allowed.isEmpty()) return allowed.stream().anyMatch(url::matches);
276	        return true;
277	    }
