292	    private boolean contentUnchanged(String url, String newHash) {
293	        if (newHash == null) return false;
294	        List<String> hashes = pageRepo.findRecentContentHashesForUrl(
295	                source.getId(), url, PageRequest.of(0, 1));
296	        return !hashes.isEmpty() && newHash.equals(hashes.get(0));
297	    }
