299	    private void markStatus(CrawlStatus status, String error) {
300	        jobRepo.findById(jobId).ifPresent(job -> {
301	            job.setStatus(status);
302	            if (error != null)               job.setErrorMessage(error);
303	            if (status == CrawlStatus.PAUSED)   job.setPausedAt(Instant.now());
304	            if (status.isTerminal())         job.setFinishedAt(Instant.now());
305	            jobRepo.save(job);
306	        });
307	    }
308	
309	    private void setStartedAt() {
310	        jobRepo.findById(jobId).ifPresent(job -> {
311	            if (job.getStartedAt() == null) {
312	                job.setStartedAt(Instant.now());
313	                jobRepo.save(job);
314	            }
315	        });
316	    }
