318	    private void updateSourceLastCrawled() {
319	        try {
320	            sourceRepo.updateLastCrawledAt(source.getId());
321	        } catch (Exception e) {
322	            log.warn("Could not update lastCrawledAt for source {}", source.getId());
323	        }
324	    }
