326	    private void saveCheckpoint(Deque<CrawlCheckpoint.PendingTarget> queue) {
327	        try {
328	            CrawlCheckpoint cp = new CrawlCheckpoint();
329	            cp.setPendingQueue(new ArrayList<>(queue));
330	            cp.setSavedAt(Instant.now());
331	            String json = objectMapper.writeValueAsString(cp);
332	            jobRepo.updateCheckpoint(jobId, json);
333	        } catch (JsonProcessingException e) {
334	            log.warn("Job {} — could not serialize checkpoint: {}", jobId, e.getMessage());
335	        }
336	    }
337	
338	    private Deque<CrawlCheckpoint.PendingTarget> loadQueue() {
339	        CrawlJob job = jobRepo.findById(jobId).orElseThrow();
340	        if (job.getCheckpoint() != null) {
341	            try {
342	                CrawlCheckpoint cp = objectMapper.readValue(job.getCheckpoint(), CrawlCheckpoint.class);
343	                if (cp.getPendingQueue() != null && !cp.getPendingQueue().isEmpty()) {
344	                    log.info("Job {} resuming from checkpoint ({} pending URLs)",
345	                            jobId, cp.getPendingQueue().size());
346	                    return new ArrayDeque<>(cp.getPendingQueue());
347	                }
348	            } catch (JsonProcessingException e) {
349	                log.warn("Job {} — invalid checkpoint JSON, starting fresh", jobId);
350	            }
351	        }
352	        Deque<CrawlCheckpoint.PendingTarget> q = new ArrayDeque<>();
353	        q.add(new CrawlCheckpoint.PendingTarget(source.getBaseUrl(), 0));
354	        return q;
355	    }
356	
357	    private Set<String> loadVisitedHashes() {
358	        return new HashSet<>(pageRepo.findVisitedUrlHashesByJobId(jobId));
359	    }
360	
361	    // Proxy references for JPA associations
362	    private CrawlJob loadJobRef() {
363	        return jobRepo.getReferenceById(jobId);
364	    }
365	    private CrawlPage loadPageRef(UUID pageId) {
366	        return pageRepo.getReferenceById(pageId);
367	    }
368	
369	    // ── Throttle ───────────────────────────────────────────────────────────
370	
371	    private void enforceThrottle() throws InterruptedException {
372	        long now     = System.currentTimeMillis();
373	        long elapsed = now - lastFetchTimeMs;
374	        long delay   = source.getDelayMsBetweenRequests();
375	        if (elapsed < delay) {
376	            Thread.sleep(delay - elapsed);
377	        }
378	        lastFetchTimeMs = System.currentTimeMillis();
379	    }
