8	 * <pre>
9	 * reslife.crawler.max-concurrent=5
10	 * reslife.crawler.fetch-timeout-seconds=30
11	 * reslife.crawler.checkpoint-interval-pages=10
12	 * reslife.crawler.user-agent=ResLife-Crawler/1.0
13	 * </pre>
