1	package com.reslife.api.domain.crawler;
2	
3	import jakarta.persistence.EntityNotFoundException;
4	import org.springframework.data.domain.Page;
5	import org.springframework.data.domain.Pageable;
6	import org.springframework.stereotype.Service;
7	import org.springframework.transaction.annotation.Transactional;
8	
9	import java.util.List;
10	import java.util.UUID;
11	
12	/**
13	 * Query and control operations for crawl jobs.
14	 *
15	 * <p>Pause/resume/cancel are delegated to {@link CrawlEngineService} which holds
16	 * the in-memory {@link CrawlJobExecution} map.  If the engine has no record of
17	 * the job (e.g. after a server restart) the DB status is updated directly so the
18	 * UI reflects the correct terminal state.
19	 */
20	@Service
21	@Transactional(readOnly = true)
22	public class CrawlJobService {
23	
24	    private final CrawlJobRepository  jobRepo;
25	    private final CrawlPageRepository pageRepo;
26	    private final CrawlEngineService  engine;
27	
28	    public CrawlJobService(CrawlJobRepository jobRepo,
29	                            CrawlPageRepository pageRepo,
30	                            CrawlEngineService engine) {
31	        this.jobRepo  = jobRepo;
32	        this.pageRepo = pageRepo;
33	        this.engine   = engine;
34	    }
35	
36	    // ── Queries ────────────────────────────────────────────────────────────
37	
38	    public Page<JobResponse> listJobs(Pageable pageable) {
39	        return jobRepo.findAllByOrderByCreatedAtDesc(pageable).map(JobResponse::from);
40	    }
41	
42	    public Page<JobResponse> listJobsBySource(UUID sourceId, Pageable pageable) {
43	        return jobRepo.findBySourceIdOrderByCreatedAtDesc(sourceId, pageable).map(JobResponse::from);
44	    }
45	
46	    public JobResponse getJob(UUID jobId) {
47	        return JobResponse.from(requireJob(jobId));
48	    }
49	
50	    public Page<PageResponse> listPages(UUID jobId, Pageable pageable) {
51	        requireJob(jobId); // 404 guard
52	        return pageRepo.findByJobIdOrderByCreatedAtDesc(jobId, pageable).map(PageResponse::from);
53	    }
54	
55	    public CrawlEngineService.EngineStatus engineStatus() {
56	        return engine.currentStatus();
57	    }
58	
59	    // ── Control ────────────────────────────────────────────────────────────
60	
61	    @Transactional
62	    public JobResponse pauseJob(UUID jobId) {
63	        CrawlJob job = requireJob(jobId);
64	        if (job.getStatus() != CrawlStatus.RUNNING) {
65	            throw new IllegalStateException("Job " + jobId + " is not RUNNING (status: " + job.getStatus() + ")");
66	        }
67	        boolean signalled = engine.pauseJob(jobId);
68	        if (!signalled) {
69	            // Engine doesn't know about this job — mark paused directly
70	            job.setStatus(CrawlStatus.PAUSED);
71	            jobRepo.save(job);
72	        }
73	        return JobResponse.from(jobRepo.findById(jobId).orElseThrow());
74	    }
75	
76	    @Transactional
77	    public JobResponse resumeJob(UUID jobId) {
78	        CrawlJob job = requireJob(jobId);
79	        if (job.getStatus() != CrawlStatus.PAUSED) {
80	            throw new IllegalStateException("Job " + jobId + " is not PAUSED (status: " + job.getStatus() + ")");
81	        }
82	        job.setStatus(CrawlStatus.PENDING);
83	        jobRepo.save(job);
84	        engine.submit(jobId);
85	        return JobResponse.from(jobRepo.findById(jobId).orElseThrow());
86	    }
87	
88	    @Transactional
89	    public JobResponse cancelJob(UUID jobId) {
90	        CrawlJob job = requireJob(jobId);
91	        if (!job.getStatus().isActive()) {
92	            throw new IllegalStateException("Job " + jobId + " is not active (status: " + job.getStatus() + ")");
93	        }
94	        boolean signalled = engine.cancelJob(jobId);
95	        if (!signalled) {
96	            job.setStatus(CrawlStatus.CANCELLED);
97	            jobRepo.save(job);
98	        }
99	        return JobResponse.from(jobRepo.findById(jobId).orElseThrow());
100	    }
101	
102	    // ── Helpers ────────────────────────────────────────────────────────────
103	
104	    private CrawlJob requireJob(UUID id) {
105	        return jobRepo.findById(id)
106	                .orElseThrow(() -> new EntityNotFoundException("CrawlJob not found: " + id));
107	    }
108	}
