1	package com.reslife.api.domain.crawler;
2	
3	import jakarta.annotation.PostConstruct;
4	import org.slf4j.Logger;
5	import org.slf4j.LoggerFactory;
6	import org.springframework.scheduling.TaskScheduler;
7	import org.springframework.scheduling.support.CronTrigger;
8	import org.springframework.stereotype.Service;
9	import org.springframework.transaction.annotation.Transactional;
10	
11	import java.time.Duration;
12	import java.util.List;
13	import java.util.UUID;
14	import java.util.concurrent.ConcurrentHashMap;
15	import java.util.concurrent.ScheduledFuture;
16	
17	/**
18	 * Manages dynamic per-source schedules.
19	 *
20	 * <p>On startup ({@link #init}) all active, scheduled sources are registered with
21	 * Spring's {@link TaskScheduler}.  When a source is created, updated, or deleted
22	 * via the admin API, {@link #rescheduleSource} / {@link #unscheduleSource} keep
23	 * the in-memory schedule map in sync.
24	 *
25	 * <p>The actual job creation and submission is delegated to
26	 * {@link #triggerScheduledJob} which checks that no job for the same source is
27	 * already running before submitting a new one.
28	 */
29	@Service
30	public class CrawlSchedulerService {
31	
32	    private static final Logger log = LoggerFactory.getLogger(CrawlSchedulerService.class);
33	
34	    private final ConcurrentHashMap<UUID, ScheduledFuture<?>> schedules = new ConcurrentHashMap<>();
35	
36	    private final TaskScheduler       taskScheduler;
37	    private final CrawlEngineService  engine;
38	    private final CrawlSourceRepository sourceRepo;
39	    private final CrawlJobRepository  jobRepo;
40	
41	    public CrawlSchedulerService(TaskScheduler taskScheduler,
42	                                  CrawlEngineService engine,
43	                                  CrawlSourceRepository sourceRepo,
44	                                  CrawlJobRepository jobRepo) {
45	        this.taskScheduler = taskScheduler;
46	        this.engine        = engine;
47	        this.sourceRepo    = sourceRepo;
48	        this.jobRepo       = jobRepo;
49	    }
50	
51	    // ── Startup ────────────────────────────────────────────────────────────
52	
53	    @PostConstruct
54	    public void init() {
55	        List<CrawlSource> active = sourceRepo.findByActiveTrueOrderByNameAsc();
56	        active.stream()
57	              .filter(CrawlSource::hasSchedule)
58	              .forEach(this::scheduleSource);
59	        log.info("Crawl scheduler initialised — {} source(s) scheduled", schedules.size());
60	    }
61	
62	    // ── Schedule management ────────────────────────────────────────────────
63	
64	    /**
65	     * Registers or replaces the schedule for a source.
66	     * No-op if the source has no cron expression and no interval.
67	     */
68	    public void rescheduleSource(CrawlSource source) {
69	        unscheduleSource(source.getId());
70	        if (source.isActive() && source.hasSchedule()) {
71	            scheduleSource(source);
72	        }
73	    }
74	
75	    /** Cancels the scheduled future for a source (if any). */
76	    public void unscheduleSource(UUID sourceId) {
77	        ScheduledFuture<?> existing = schedules.remove(sourceId);
78	        if (existing != null) {
79	            existing.cancel(false);
80	            log.debug("Unscheduled source {}", sourceId);
81	        }
82	    }
83	
84	    // ── Helpers ────────────────────────────────────────────────────────────
85	
86	    private void scheduleSource(CrawlSource source) {
87	        Runnable task = () -> triggerScheduledJob(source.getId());
88	
89	        ScheduledFuture<?> future;
90	        if (source.getScheduleCron() != null) {
91	            future = taskScheduler.schedule(task, new CronTrigger(source.getScheduleCron()));
92	            log.info("Source '{}' scheduled with cron '{}'", source.getName(), source.getScheduleCron());
93	        } else {
94	            Duration interval = Duration.ofSeconds(source.getScheduleIntervalSeconds());
95	            future = taskScheduler.scheduleAtFixedRate(task, interval);
96	            log.info("Source '{}' scheduled every {} seconds", source.getName(), source.getScheduleIntervalSeconds());
97	        }
98	        schedules.put(source.getId(), future);
99	    }
100	
101	    @Transactional
102	    void triggerScheduledJob(UUID sourceId) {
103	        CrawlSource source = sourceRepo.findById(sourceId).orElse(null);
104	        if (source == null || !source.isActive()) {
105	            unscheduleSource(sourceId);
106	            return;
107	        }
108	
109	        // Prevent duplicate concurrent runs for the same source
110	        boolean alreadyRunning = jobRepo.findFirstBySourceIdAndStatusIn(
111	                sourceId, List.of(CrawlStatus.PENDING, CrawlStatus.RUNNING)).isPresent();
112	        if (alreadyRunning) {
113	            log.debug("Skipping scheduled trigger for '{}' — a job is already active", source.getName());
114	            return;
115	        }
116	
117	        CrawlJob job = new CrawlJob();
118	        job.setSource(source);
119	        job.setTriggerType(TriggerType.SCHEDULED);
120	        job.setStatus(CrawlStatus.PENDING);
121	        jobRepo.save(job);
122	
123	        engine.submit(job.getId());
124	        log.info("Scheduled trigger fired for source '{}' — job {}", source.getName(), job.getId());
125	    }
126	}
