271	    private boolean isAllowed(String url) {
272	        List<String> blocked = config.getBlockedPathPatterns();
273	        if (!blocked.isEmpty() && blocked.stream().anyMatch(url::matches)) return false;
274	        List<String> allowed = config.getAllowedPathPatterns();
275	        if (!allowed.isEmpty()) return allowed.stream().anyMatch(url::matches);
276	        return true;
277	    }
