195	    private void extractAndSaveItems(UUID pageId, FetchResult result) {
196	        if (result.body() == null || result.body().isBlank()) return;
197	
198	        // Keyword filter — if keywords are configured, only save items that match
199	        List<String> keywords = config.getKeywords();
200	        if (!keywords.isEmpty()) {
201	            String bodyLower = result.body().toLowerCase();
202	            boolean matches = keywords.stream().anyMatch(kw -> bodyLower.contains(kw.toLowerCase()));
203	            if (!matches) return;
204	        }
205	
206	        String itemSel = config.getItemSelector();
207	        if (itemSel != null && !itemSel.isBlank()) {
208	            // Structured extraction: itemSelector is interpreted as a JSON Pointer
209	            // (RFC 6901, e.g. "/results" or "/data/items") when the response body is
210	            // valid JSON. titleSelector and linkSelector are also JSON Pointers within
211	            // each element.
212	            //
213	            // CSS selector / XPath support for HTML responses is NOT implemented here —
214	            // it requires a DOM parser (e.g. Jsoup) that is not in the current dependency
215	            // stack. When itemSelector is set but the body is not valid JSON, or the
216	            // selector does not start with '/' (i.e. is not a JSON Pointer), extraction
217	            // falls back to saving the full body as a single item.
218	            if (tryExtractFromJson(pageId, result, itemSel)) {
219	                return;
220	            }
221	            log.debug("Job {} — itemSelector '{}' set but body is not JSON or selector is not a " +
222	                      "JSON Pointer; falling back to full-body mode for {}", jobId, itemSel, result.url());
223	        }
224	
225	        // Default / fallback: wrap the full body as a single item
226	        saveItem(pageId, result.url(), result.body(), null, null);
227	    }
