229	    /**
230	     * Attempts to extract multiple items from a JSON response body using JSON Pointer selectors.
231	     *
232	     * <p>Returns {@code true} if the body was valid JSON and extraction ran (even if zero items
233	     * were found or the pointer pointed to a non-array), {@code false} if the body could not
234	     * be parsed as JSON so the caller can fall back to full-body mode.
235	     */
236	    private boolean tryExtractFromJson(UUID pageId, FetchResult result, String itemSel) {
237	        JsonNode root;
238	        try {
239	            root = objectMapper.readTree(result.body());
240	        } catch (JsonProcessingException e) {
241	            return false; // not JSON — caller should fall back
242	        }
243	
244	        if (!itemSel.startsWith("/")) {
245	            // Not a JSON Pointer — likely a CSS selector intended for HTML.
246	            // CSS evaluation is not supported without a DOM parser.
247	            log.debug("Job {} — itemSelector '{}' does not start with '/' so it cannot be " +
248	                      "evaluated as a JSON Pointer; CSS selectors require a DOM parser " +
249	                      "(e.g. Jsoup) not currently in the dependency stack", jobId, itemSel);
250	            return false;
251	        }
252	
253	        JsonNode items = root.at(itemSel);
254	        if (!items.isArray()) {
255	            // Pointer resolved but not to an array; save the pointed-to node as one item
256	            String body = items.isMissingNode() ? result.body() : items.toString();
257	            saveItem(pageId, result.url(), body, null, null);
258	            return true;
259	        }
260	
261	        String titleSel = config.getTitleSelector();
262	        String linkSel  = config.getLinkSelector();
263	
264	        for (JsonNode node : items) {
265	            String title   = extractJsonPointerField(node, titleSel);
266	            String link    = extractJsonPointerField(node, linkSel);
267	            String itemUrl = (link != null && !link.isBlank()) ? link : result.url();
268	            String body;
269	            try {
270	                body = objectMapper.writeValueAsString(node);
271	            } catch (JsonProcessingException e) {
272	                body = node.toString();
273	            }
274	            saveItem(pageId, itemUrl, body, title, link);
275	        }
276	        return true;
277	    }
278	
279	    /**
280	     * Extracts a text value from a JSON node using a JSON Pointer (RFC 6901) selector.
281	     * Returns {@code null} if the selector is blank, not a pointer (doesn't start with '/'),
282	     * or the node is missing/null.
283	     */
284	    private String extractJsonPointerField(JsonNode node, String selector) {
285	        if (selector == null || selector.isBlank() || !selector.startsWith("/")) return null;
286	        JsonNode found = node.at(selector);
287	        return (found.isMissingNode() || found.isNull()) ? null : found.asText();
288	    }
