292	     * {@code title} and {@code link} are included in the JSON envelope when non-null, so that
293	     * consumers can read structured fields without re-parsing the full body.
294	     */
295	    private void saveItem(UUID pageId, String url, String body, String title, String link) {
296	        try {
297	            // LinkedHashMap preserves insertion order in the serialized JSON
298	            Map<String, Object> dataMap = new LinkedHashMap<>();
299	            dataMap.put("url",       url);
300	            if (title != null) dataMap.put("title", title);
301	            if (link  != null) dataMap.put("link",  link);
302	            dataMap.put("body",      body);
303	            dataMap.put("sourceId",  source.getId().toString());
304	            dataMap.put("crawledAt", Instant.now().toString());
305	
306	            String rawData  = objectMapper.writeValueAsString(dataMap);
307	            String dataHash = CrawlFetcherService.sha256(rawData);
308	
309	            boolean isNew = itemRepo.findFirstBySourceIdAndDataHash(source.getId(), dataHash).isEmpty();
310	
311	            CrawlItem item = new CrawlItem();
312	            item.setSource(source);
313	            item.setJob(loadJobRef());
314	            item.setPage(loadPageRef(pageId));
315	            item.setUrl(url);
316	            item.setDataHash(dataHash);
317	            item.setRawData(rawData);
318	            item.setNew(isNew);
319	            itemRepo.save(item);
320	            jobRepo.incrementItemsFound(jobId);
321	
322	        } catch (JsonProcessingException e) {
323	            log.warn("Job {} — could not serialize item for {}: {}", jobId, url, e.getMessage());
324	        }
325	    }
