360	    private List<String> extractHrefs(String body, String baseUrl) {
361	        List<String> result = new ArrayList<>();
362	        Matcher m = HREF.matcher(body);
363	        while (m.find()) {
364	            try {
365	                String href = m.group(1).trim();
366	                if (href.startsWith("javascript:") || href.startsWith("mailto:")) continue;
367	                URI resolved = URI.create(baseUrl).resolve(href);
368	                String url = resolved.toASCIIString();
369	                // Strip fragment
370	                int frag = url.indexOf('#');
371	                if (frag > 0) url = url.substring(0, frag);
372	                result.add(url);
373	            } catch (Exception ignored) {}
374	        }
375	        return result.stream().distinct().toList();
376	    }
