378	    private boolean isAllowed(String url) {
379	        List<String> blocked = config.getBlockedPathPatterns();
380	        if (!blocked.isEmpty() && blocked.stream().anyMatch(url::matches)) return false;
381	        List<String> allowed = config.getAllowedPathPatterns();
382	        if (!allowed.isEmpty()) return allowed.stream().anyMatch(url::matches);
383	        return true;
384	    }
