14	/**
15	 * Computes and caches the four core analytics metrics.
16	 *
17	 * <p>All four metrics are computed on startup ({@link #refreshOnStartup}) and
18	 * then automatically every 15 minutes ({@link #scheduledRefresh}).  Each result
19	 * is serialised to JSON and stored in {@code analytics_snapshots} as a single
20	 * row keyed by metric name — this lets the read path return pre-computed data
21	 * without hitting multiple large tables on every dashboard request.
22	 *
23	 * <h3>Metrics</h3>
24	 * <ul>
25	 *   <li><b>booking_conversion</b> — SIGNED / non-pending housing agreements × 100.</li>
26	 *   <li><b>no_show_rate</b> — NO_SHOW / all decided move-in records × 100.</li>
27	 *   <li><b>slot_utilization</b> — currently CHECKED_IN rooms / total known rooms, by building.</li>
28	 *   <li><b>settlement_completion</b> — acknowledged / total acknowledgment-required
29	 *       SETTLEMENT + ARBITRATION notifications × 100.</li>
30	 * </ul>
31	 */
32	@Service
33	public class AnalyticsComputeService {
34	
35	    private static final Logger log = LoggerFactory.getLogger(AnalyticsComputeService.class);
36	
37	    private static final String BOOKING_CONVERSION    = "booking_conversion";
38	    private static final String NO_SHOW_RATE          = "no_show_rate";
39	    private static final String SLOT_UTILIZATION      = "slot_utilization";
40	    private static final String SETTLEMENT_COMPLETION = "settlement_completion";
41	
42	    private final JdbcTemplate                 jdbc;
43	    private final AnalyticsSnapshotRepository  snapshotRepo;
44	    private final ObjectMapper                 objectMapper;
45	
46	    public AnalyticsComputeService(JdbcTemplate jdbc,
47	                                    AnalyticsSnapshotRepository snapshotRepo,
48	                                    ObjectMapper objectMapper) {
49	        this.jdbc         = jdbc;
50	        this.snapshotRepo = snapshotRepo;
51	        this.objectMapper = objectMapper;
52	    }
53	
54	    // ── Lifecycle ──────────────────────────────────────────────────────────
55	
56	    @PostConstruct
57	    public void refreshOnStartup() {
58	        refresh();
59	    }
60	
61	    @Scheduled(fixedDelay = 900_000) // 15 minutes after last completion
62	    public void scheduledRefresh() {
63	        refresh();
64	    }
65	
66	    /** Computes all four metrics and persists them. */
67	    public void refresh() {
68	        long start = System.currentTimeMillis();
69	        try {
70	            saveSnapshot(BOOKING_CONVERSION,    computeBookingConversion());
71	            saveSnapshot(NO_SHOW_RATE,          computeNoShowRate());
72	            saveSnapshot(SLOT_UTILIZATION,      computeSlotUtilization());
73	            saveSnapshot(SETTLEMENT_COMPLETION, computeSettlementCompletion());
74	            log.info("Analytics refresh complete in {}ms", System.currentTimeMillis() - start);
75	        } catch (Exception e) {
76	            log.error("Analytics refresh failed: {}", e.getMessage(), e);
77	        }
78	    }
