223	    // ── Persistence ────────────────────────────────────────────────────────
224	
225	    private void saveSnapshot(String metricName, Map<String, Object> data) {
226	        try {
227	            String json = objectMapper.writeValueAsString(data);
228	            AnalyticsSnapshot snap = snapshotRepo.findByMetricName(metricName)
229	                .orElseGet(AnalyticsSnapshot::new);
230	            snap.setMetricName(metricName);
231	            snap.setValue(json);
232	            snap.setComputedAt(Instant.now());
233	            snapshotRepo.save(snap);
234	        } catch (Exception e) {
235	            log.warn("Could not save snapshot for '{}': {}", metricName, e.getMessage());
236	        }
237	    }
