1	package com.reslife.api.admin;
2	
3	import com.fasterxml.jackson.core.type.TypeReference;
4	import com.fasterxml.jackson.databind.ObjectMapper;
5	import com.reslife.api.domain.analytics.AnalyticsComputeService;
6	import com.reslife.api.domain.analytics.AnalyticsSnapshot;
7	import com.reslife.api.domain.analytics.AnalyticsSnapshotRepository;
8	import org.slf4j.Logger;
9	import org.slf4j.LoggerFactory;
10	import org.springframework.http.HttpStatus;
11	import org.springframework.web.bind.annotation.*;
12	
13	import java.util.LinkedHashMap;
14	import java.util.List;
15	import java.util.Map;
16	
17	/**
18	 * Admin-only REST endpoints for the analytics dashboard.
19	 *
20	 * <pre>
21	 * GET  /api/admin/analytics         — all four metrics (pre-computed)
22	 * POST /api/admin/analytics/refresh — trigger an immediate recompute
23	 * </pre>
24	 *
25	 * <p>The GET endpoint is intentionally cheap: it reads four rows from
26	 * {@code analytics_snapshots} and returns them.  Heavy computation is done
27	 * by the scheduled {@link AnalyticsComputeService} in the background.
28	 */
29	@RestController
30	@RequestMapping("/api/admin/analytics")
31	public class AnalyticsAdminController {
32	
33	    private static final Logger log = LoggerFactory.getLogger(AnalyticsAdminController.class);
34	
35	    private static final List<String> METRIC_NAMES = List.of(
36	            "booking_conversion",
37	            "no_show_rate",
38	            "slot_utilization",
39	            "settlement_completion"
40	    );
41	
42	    private final AnalyticsSnapshotRepository snapshotRepo;
43	    private final AnalyticsComputeService     computeService;
44	    private final ObjectMapper                objectMapper;
45	
46	    public AnalyticsAdminController(AnalyticsSnapshotRepository snapshotRepo,
47	                                     AnalyticsComputeService computeService,
48	                                     ObjectMapper objectMapper) {
49	        this.snapshotRepo   = snapshotRepo;
50	        this.computeService = computeService;
51	        this.objectMapper   = objectMapper;
52	    }
53	
54	    /**
55	     * Returns all four analytics metrics as a single JSON object.
56	     *
57	     * <p>Each key is the snake_case metric name; each value contains:
58	     * <ul>
59	     *   <li>{@code data} — the metric payload (structure depends on metric)</li>
60	     *   <li>{@code computedAt} — ISO-8601 timestamp of last compute</li>
61	     * </ul>
62	     */
63	    @GetMapping
64	    public Map<String, Object> dashboard() {
65	        Map<String, Object> result = new LinkedHashMap<>();
66	        for (AnalyticsSnapshot snap : snapshotRepo.findAll()) {
67	            try {
68	                Map<String, Object> parsed = objectMapper.readValue(
69	                        snap.getValue(), new TypeReference<>() {});
70	                Map<String, Object> entry = new LinkedHashMap<>();
71	                entry.put("data",        parsed);
72	                entry.put("computedAt",  snap.getComputedAt());
73	                result.put(snap.getMetricName(), entry);
74	            } catch (Exception e) {
75	                log.warn("Could not deserialise snapshot '{}': {}", snap.getMetricName(), e.getMessage());
76	                result.put(snap.getMetricName(), Map.of("error", "Parse error"));
77	            }
78	        }
79	        return result;
80	    }
81	
82	    /**
83	     * Forces an immediate recompute of all metrics.
84	     * Useful after bulk data imports or for testing.
85	     */
86	    @PostMapping("/refresh")
87	    @ResponseStatus(HttpStatus.NO_CONTENT)
88	    public void refresh() {
89	        computeService.refresh();
90	    }
91	}
