1	package com.reslife.api.domain.analytics;
2	
3	import com.fasterxml.jackson.databind.ObjectMapper;
4	import jakarta.annotation.PostConstruct;
5	import org.slf4j.Logger;
6	import org.slf4j.LoggerFactory;
7	import org.springframework.jdbc.core.JdbcTemplate;
8	import org.springframework.scheduling.annotation.Scheduled;
9	import org.springframework.stereotype.Service;
10	
11	import java.time.Instant;
12	import java.util.*;
13	
14	/**
15	 * Computes and caches the four core analytics metrics.
16	 *
17	 * <p>All four metrics are computed on startup ({@link #refreshOnStartup}) and
18	 * then automatically every 15 minutes ({@link #scheduledRefresh}).  Each result
19	 * is serialised to JSON and stored in {@code analytics_snapshots} as a single
20	 * row keyed by metric name — this lets the read path return pre-computed data
21	 * without hitting multiple large tables on every dashboard request.
22	 *
23	 * <h3>Metrics</h3>
24	 * <ul>
25	 *   <li><b>booking_conversion</b> — SIGNED / non-pending housing agreements × 100.</li>
26	 *   <li><b>no_show_rate</b> — NO_SHOW / all decided move-in records × 100.</li>
27	 *   <li><b>slot_utilization</b> — currently CHECKED_IN rooms / total known rooms, by building.</li>
28	 *   <li><b>settlement_completion</b> — acknowledged / total acknowledgment-required
29	 *       SETTLEMENT + ARBITRATION notifications × 100.</li>
30	 * </ul>
31	 */
32	@Service
33	public class AnalyticsComputeService {
34	
35	    private static final Logger log = LoggerFactory.getLogger(AnalyticsComputeService.class);
36	
37	    private static final String BOOKING_CONVERSION    = "booking_conversion";
38	    private static final String NO_SHOW_RATE          = "no_show_rate";
39	    private static final String SLOT_UTILIZATION      = "slot_utilization";
40	    private static final String SETTLEMENT_COMPLETION = "settlement_completion";
41	
42	    private final JdbcTemplate                 jdbc;
43	    private final AnalyticsSnapshotRepository  snapshotRepo;
44	    private final ObjectMapper                 objectMapper;
45	
46	    public AnalyticsComputeService(JdbcTemplate jdbc,
47	                                    AnalyticsSnapshotRepository snapshotRepo,
48	                                    ObjectMapper objectMapper) {
49	        this.jdbc         = jdbc;
50	        this.snapshotRepo = snapshotRepo;
51	        this.objectMapper = objectMapper;
52	    }
53	
54	    // ── Lifecycle ──────────────────────────────────────────────────────────
55	
56	    @PostConstruct
57	    public void refreshOnStartup() {
58	        refresh();
59	    }
60	
61	    @Scheduled(fixedDelay = 900_000) // 15 minutes after last completion
62	    public void scheduledRefresh() {
63	        refresh();
64	    }
65	
66	    /** Computes all four metrics and persists them. */
67	    public void refresh() {
68	        long start = System.currentTimeMillis();
69	        try {
70	            saveSnapshot(BOOKING_CONVERSION,    computeBookingConversion());
71	            saveSnapshot(NO_SHOW_RATE,          computeNoShowRate());
72	            saveSnapshot(SLOT_UTILIZATION,      computeSlotUtilization());
73	            saveSnapshot(SETTLEMENT_COMPLETION, computeSettlementCompletion());
74	            log.info("Analytics refresh complete in {}ms", System.currentTimeMillis() - start);
75	        } catch (Exception e) {
76	            log.error("Analytics refresh failed: {}", e.getMessage(), e);
77	        }
78	    }
79	
80	    // ── Metric computations ────────────────────────────────────────────────
81	
82	    private Map<String, Object> computeBookingConversion() {
83	        // Totals by status
84	        Map<String, Long> byStatus = new LinkedHashMap<>();
85	        jdbc.queryForList("SELECT status, COUNT(*) AS cnt FROM housing_agreements GROUP BY status ORDER BY status")
86	            .forEach(r -> byStatus.put((String) r.get("status"), toLong(r.get("cnt"))));
87	
88	        long signed    = byStatus.getOrDefault("SIGNED",    0L);
89	        long expired   = byStatus.getOrDefault("EXPIRED",   0L);
90	        long cancelled = byStatus.getOrDefault("CANCELLED", 0L);
91	        long decided   = signed + expired + cancelled;
92	        double rate    = decided > 0 ? Math.round((signed * 1000.0 / decided)) / 10.0 : 0.0;
93	
94	        // Monthly SIGNED count over last 6 months
95	        List<Map<String, Object>> monthlyTrend = jdbc.queryForList(
96	            "SELECT TO_CHAR(DATE_TRUNC('month', created_at), 'YYYY-MM') AS month, " +
97	            "       COUNT(*) AS cnt " +
98	            "FROM   housing_agreements " +
99	            "WHERE  status = 'SIGNED' " +
100	            "  AND  created_at >= NOW() - INTERVAL '6 months' " +
101	            "GROUP  BY month ORDER BY month"
102	        );
103	
104	        Map<String, Object> result = new LinkedHashMap<>();
105	        result.put("byStatus",       byStatus);
106	        result.put("signed",         signed);
107	        result.put("expired",        expired);
108	        result.put("cancelled",      cancelled);
109	        result.put("pending",        byStatus.getOrDefault("PENDING", 0L));
110	        result.put("conversionRate", rate);
111	        result.put("monthlyTrend",   monthlyTrend);
112	        return result;
113	    }
114	
115	    private Map<String, Object> computeNoShowRate() {
116	        Map<String, Long> byStatus = new LinkedHashMap<>();
117	        jdbc.queryForList("SELECT check_in_status, COUNT(*) AS cnt FROM move_in_records GROUP BY check_in_status ORDER BY check_in_status")
118	            .forEach(r -> byStatus.put((String) r.get("check_in_status"), toLong(r.get("cnt"))));
119	
120	        long noShow    = byStatus.getOrDefault("NO_SHOW",     0L);
121	        long checkedIn = byStatus.getOrDefault("CHECKED_IN",  0L);
122	        long checkedOut= byStatus.getOrDefault("CHECKED_OUT", 0L);
123	        long cancelled = byStatus.getOrDefault("CANCELLED",   0L);
124	        long decided   = noShow + checkedIn + checkedOut + cancelled; // excludes PENDING
125	        double rate    = decided > 0 ? Math.round((noShow * 1000.0 / decided)) / 10.0 : 0.0;
126	
127	        // Monthly no-show count and totals over last 6 months
128	        List<Map<String, Object>> monthlyTrend = jdbc.queryForList(
129	            "SELECT TO_CHAR(DATE_TRUNC('month', created_at), 'YYYY-MM') AS month, " +
130	            "       COUNT(*) FILTER (WHERE check_in_status = 'NO_SHOW')  AS no_shows, " +
131	            "       COUNT(*) FILTER (WHERE check_in_status != 'PENDING') AS decided " +
132	            "FROM   move_in_records " +
133	            "WHERE  created_at >= NOW() - INTERVAL '6 months' " +
134	            "GROUP  BY month ORDER BY month"
135	        );
136	
137	        Map<String, Object> result = new LinkedHashMap<>();
138	        result.put("byStatus",     byStatus);
139	        result.put("noShow",       noShow);
140	        result.put("checkedIn",    checkedIn);
141	        result.put("checkedOut",   checkedOut);
142	        result.put("cancelled",    cancelled);
143	        result.put("noShowRate",   rate);
144	        result.put("monthlyTrend", monthlyTrend);
145	        return result;
146	    }
147	
148	    private Map<String, Object> computeSlotUtilization() {
149	        // Per-building: occupied (CHECKED_IN with no past move-out) and total known rooms
150	        List<Map<String, Object>> perBuilding = jdbc.queryForList(
151	            "SELECT building_name, " +
152	            "       COUNT(DISTINCT room_number) FILTER (" +
153	            "           WHERE check_in_status = 'CHECKED_IN' " +
154	            "             AND (move_out_date IS NULL OR move_out_date >= CURRENT_DATE)" +
155	            "       ) AS occupied, " +
156	            "       COUNT(DISTINCT room_number) AS total " +
157	            "FROM   move_in_records " +
158	            "GROUP  BY building_name ORDER BY building_name"
159	        );
160	
161	        long totalOccupied = 0, totalSlots = 0;
162	        List<Map<String, Object>> byBuilding = new ArrayList<>();
163	        for (Map<String, Object> row : perBuilding) {
164	            long occ   = toLong(row.get("occupied"));
165	            long total = toLong(row.get("total"));
166	            totalOccupied += occ;
167	            totalSlots    += total;
168	            double bRate   = total > 0 ? Math.round((occ * 1000.0 / total)) / 10.0 : 0.0;
169	            Map<String, Object> entry = new LinkedHashMap<>();
170	            entry.put("building",         row.get("building_name"));
171	            entry.put("occupied",         occ);
172	            entry.put("total",            total);
173	            entry.put("utilizationRate",  bRate);
174	            byBuilding.add(entry);
175	        }
176	        double overallRate = totalSlots > 0
177	                ? Math.round((totalOccupied * 1000.0 / totalSlots)) / 10.0 : 0.0;
178	
179	        Map<String, Object> result = new LinkedHashMap<>();
180	        result.put("occupiedSlots",    totalOccupied);
181	        result.put("totalSlots",       totalSlots);
182	        result.put("utilizationRate",  overallRate);
183	        result.put("byBuilding",       byBuilding);
184	        return result;
185	    }
186	
187	    private Map<String, Object> computeSettlementCompletion() {
188	        List<Map<String, Object>> rows = jdbc.queryForList(
189	            "SELECT category, " +
190	            "       COUNT(*)              AS total, " +
191	            "       COUNT(acknowledged_at) AS completed " +
192	            "FROM   notifications " +
193	            "WHERE  requires_acknowledgment = TRUE " +
194	            "  AND  category IN ('SETTLEMENT', 'ARBITRATION') " +
195	            "GROUP  BY category ORDER BY category"
196	        );
197	
198	        long totalRequired = 0, totalCompleted = 0;
199	        Map<String, Map<String, Object>> byCategory = new LinkedHashMap<>();
200	        for (Map<String, Object> row : rows) {
201	            long t = toLong(row.get("total"));
202	            long c = toLong(row.get("completed"));
203	            totalRequired  += t;
204	            totalCompleted += c;
205	            Map<String, Object> cat = new LinkedHashMap<>();
206	            cat.put("total",     t);
207	            cat.put("completed", c);
208	            cat.put("pending",   t - c);
209	            byCategory.put((String) row.get("category"), cat);
210	        }
211	        double rate = totalRequired > 0
212	                ? Math.round((totalCompleted * 1000.0 / totalRequired)) / 10.0 : 0.0;
213	
214	        Map<String, Object> result = new LinkedHashMap<>();
215	        result.put("totalRequired",   totalRequired);
216	        result.put("totalCompleted",  totalCompleted);
217	        result.put("totalPending",    totalRequired - totalCompleted);
218	        result.put("completionRate",  rate);
219	        result.put("byCategory",      byCategory);
220	        return result;
221	    }
222	
223	    // ── Persistence ────────────────────────────────────────────────────────
224	
225	    private void saveSnapshot(String metricName, Map<String, Object> data) {
226	        try {
227	            String json = objectMapper.writeValueAsString(data);
228	            AnalyticsSnapshot snap = snapshotRepo.findByMetricName(metricName)
229	                .orElseGet(AnalyticsSnapshot::new);
230	            snap.setMetricName(metricName);
231	            snap.setValue(json);
232	            snap.setComputedAt(Instant.now());
233	            snapshotRepo.save(snap);
234	        } catch (Exception e) {
235	            log.warn("Could not save snapshot for '{}': {}", metricName, e.getMessage());
236	        }
237	    }
238	
239	    // ── Utilities ──────────────────────────────────────────────────────────
240	
241	    private static long toLong(Object value) {
242	        if (value == null) return 0L;
243	        return ((Number) value).longValue();
244	    }
245	}
