4	// ── Helpers ───────────────────────────────────────────────────────────────
5	
6	function fmt(iso) {
7	  if (!iso) return '—';
8	  return new Date(iso).toLocaleString(undefined, { dateStyle: 'medium', timeStyle: 'short' });
9	}
10	
11	function pct(v) {
12	  if (v == null) return '0%';
13	  return `${Number(v).toFixed(1)}%`;
14	}
15	
16	// ── Reusable primitives ───────────────────────────────────────────────────
17	
18	function StatCard({ label, value, sub, color = '#111', bg = '#fff' }) {
19	  return (
20	    <div style={{ padding: '1rem 1.2rem', border: '1px solid #eee', borderRadius: 8, background: bg, minWidth: 110 }}>
21	      <div style={{ fontSize: '1.8rem', fontWeight: 700, color, lineHeight: 1.1 }}>{value}</div>
22	      <div style={{ fontSize: '0.8rem', color: '#666', marginTop: 3 }}>{label}</div>
23	      {sub && <div style={{ fontSize: '0.72rem', color: '#aaa', marginTop: 2 }}>{sub}</div>}
24	    </div>
25	  );
26	}
27	
28	function PercentBar({ value = 0, color = '#0055cc', bg = '#e8edf8' }) {
29	  const w = Math.min(Math.max(value, 0), 100);
30	  return (
31	    <div style={{ background: bg, borderRadius: 99, height: 10, overflow: 'hidden', flex: 1 }}>
32	      <div style={{ background: color, height: '100%', width: `${w}%`, borderRadius: 99, transition: 'width .4s ease' }} />
33	    </div>
34	  );
35	}
36	
37	/** Simple SVG bar chart — no external library. */
38	function BarChart({ data = [], valueKey = 'cnt', labelKey = 'month', color = '#0055cc', height = 90 }) {
39	  if (!data.length) return <div style={{ color: '#bbb', fontSize: '0.8rem', padding: '1rem 0' }}>No data</div>;
40	
41	  const W = 340, H = height, PAD = 20;
42	  const vals = data.map(d => Number(d[valueKey]) || 0);
43	  const max = Math.max(...vals, 1);
44	  const barW = Math.floor((W - PAD) / data.length) - 3;
45	
46	  return (
47	    <svg viewBox={`0 0 ${W} ${H + 16}`} style={{ width: '100%', maxWidth: W, overflow: 'visible' }}>
48	      {data.map((d, i) => {
49	        const val  = Number(d[valueKey]) || 0;
50	        const barH = Math.max(((val / max) * (H - PAD)), 2);
51	        const x    = PAD / 2 + i * (barW + 3);
52	        const y    = H - barH;
53	        return (
54	          <g key={i}>
55	            <rect x={x} y={y} width={barW} height={barH} fill={color} rx={2} opacity={0.85} />
56	            {val > 0 && (
57	              <text x={x + barW / 2} y={y - 3} textAnchor="middle" fontSize="9" fill={color} fontWeight="600">
58	                {val}
59	              </text>
60	            )}
61	            <text x={x + barW / 2} y={H + 13} textAnchor="middle" fontSize="8" fill="#999">
62	              {String(d[labelKey]).slice(-5)}
63	            </text>
64	          </g>
65	        );
66	      })}
67	    </svg>
68	  );
69	}
70	
71	function SectionHeader({ title, computedAt }) {
72	  return (
73	    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'baseline', marginBottom: '0.8rem' }}>
74	      <h3 style={{ margin: 0, fontSize: '1rem', fontWeight: 700 }}>{title}</h3>
75	      {computedAt && <span style={{ fontSize: '0.72rem', color: '#aaa' }}>Updated {fmt(computedAt)}</span>}
76	    </div>
77	  );
78	}
