65	        String result = pattern;
66	        for (java.util.Map.Entry<String, String> e : vars.entrySet()) {
67	            result = result.replace("{{" + e.getKey() + "}}", e.getValue() != null ? e.getValue() : "");
68	        }
69	        return result;
70	    }
71	}
