1	package com.reslife.api.domain.notification;
2	
3	import com.reslife.api.domain.user.User;
4	import com.reslife.api.domain.user.UserService;
5	import jakarta.persistence.EntityNotFoundException;
6	import org.slf4j.Logger;
7	import org.slf4j.LoggerFactory;
8	import org.springframework.data.domain.Page;
9	import org.springframework.data.domain.Pageable;
10	import org.springframework.stereotype.Service;
11	import org.springframework.transaction.annotation.Transactional;
12	
13	import java.util.List;
14	import java.util.Map;
15	import java.util.UUID;
16	
17	/**
18	 * Manages creation, delivery, acknowledgment, and read-state of notifications.
19	 *
20	 * <h3>Delivery model</h3>
21	 * <p>Notifications are local-only: stored in PostgreSQL and polled / fetched
22	 * by the React frontend.  No email, push, or external delivery is performed.
23	 *
24	 * <h3>Template rendering</h3>
25	 * <p>Templates are loaded from the {@code notification_templates} table.
26	 * Variables use {@code {{key}}} placeholders; rendered text is stored on
27	 * the {@link Notification} record for immutable audit history.  The raw
28	 * variable map is also stored so the original substitution values are auditable.
29	 *
30	 * <h3>Acknowledgment</h3>
31	 * <p>When {@link Notification#isRequiresAcknowledgment()} is true the recipient
32	 * must explicitly call {@link #acknowledge}.  Each acknowledgment is recorded
33	 * in {@code notification_acknowledgments} with session and IP address for audit.
34	 */
35	@Service
36	@Transactional(readOnly = true)
37	public class NotificationService {
38	
39	    private static final Logger log = LoggerFactory.getLogger(NotificationService.class);
40	
41	    private final NotificationRepository             notifRepo;
42	    private final NotificationTemplateRepository     templateRepo;
43	    private final NotificationAcknowledgmentRepository ackRepo;
44	    private final UserService                        userService;
45	
46	    public NotificationService(NotificationRepository notifRepo,
47	                               NotificationTemplateRepository templateRepo,
48	                               NotificationAcknowledgmentRepository ackRepo,
49	                               UserService userService) {
50	        this.notifRepo    = notifRepo;
51	        this.templateRepo = templateRepo;
52	        this.ackRepo      = ackRepo;
53	        this.userService  = userService;
54	    }
55	
56	    // ── Inbox ──────────────────────────────────────────────────────────────────
57	
58	    /**
59	     * Returns a paginated inbox for the recipient.
60	     *
61	     * @param unreadOnly  if true, returns only unread items
62	     * @param category    optional category filter
63	     * @param pageable    page/size/sort
64	     */
65	    public Page<Notification> findInbox(UUID recipientId, boolean unreadOnly,
66	                                        NotificationCategory category, Pageable pageable) {
67	        Boolean readFilter = unreadOnly ? Boolean.FALSE : null;
68	        return notifRepo.findInbox(recipientId, readFilter, category, pageable);
69	    }
70	
71	    /** Counts unread and pending-acknowledgment totals for badge display. */
72	    public NotificationCountResponse counts(UUID recipientId) {
73	        long unread = notifRepo.countByRecipientIdAndReadFalse(recipientId);
74	        long pendingAck = notifRepo.countByRecipientIdAndRequiresAcknowledgmentTrueAndAcknowledgedAtIsNull(recipientId);
75	        return new NotificationCountResponse(unread, pendingAck);
76	    }
77	
78	    public Notification findById(UUID id, UUID requesterId) {
79	        Notification n = notifRepo.findById(id)
80	                .orElseThrow(() -> new EntityNotFoundException("Notification not found: " + id));
81	        if (!n.getRecipient().getId().equals(requesterId)) {
82	            throw new EntityNotFoundException("Notification not found: " + id);
83	        }
84	        return n;
85	    }
86	
87	    // ── Read state ─────────────────────────────────────────────────────────────
88	
89	    @Transactional
90	    public NotificationResponse markRead(UUID notificationId, UUID recipientId) {
91	        Notification n = findById(notificationId, recipientId);
92	        if (!n.isRead()) {
93	            n.markRead();
94	            notifRepo.save(n);
95	        }
96	        return NotificationResponse.from(n);
97	    }
98	
99	    @Transactional
100	    public int markAllRead(UUID recipientId) {
101	        return notifRepo.markAllReadForRecipient(recipientId);
102	    }
103	
104	    // ── Acknowledgment ─────────────────────────────────────────────────────────
105	
106	    /**
107	     * Records an acknowledgment for a notification that requires one.
108	     *
109	     * <p>Idempotent: if the recipient has already acknowledged, returns the
110	     * existing notification state without inserting a duplicate audit row.
111	     *
112	     * @param sessionId  Spring Session ID (for audit)
113	     * @param ipAddress  remote address (for audit)
114	     */
115	    @Transactional
116	    public NotificationResponse acknowledge(UUID notificationId, UUID recipientId,
117	                                            String sessionId, String ipAddress) {
118	        Notification n = findById(notificationId, recipientId);
119	
120	        if (!n.isRequiresAcknowledgment()) {
121	            throw new IllegalArgumentException(
122	                    "Notification does not require acknowledgment.");
123	        }
124	
125	        if (n.isAcknowledged()) {
126	            log.debug("Notification {} already acknowledged by {}", notificationId, recipientId);
127	            return NotificationResponse.from(n);
128	        }
129	
130	        // Mark the notification itself
131	        n.markAcknowledged();
132	        notifRepo.save(n);
133	
134	        // Insert immutable audit record
135	        NotificationAcknowledgment audit = new NotificationAcknowledgment(
136	                notificationId, recipientId, sessionId, ipAddress);
137	        ackRepo.save(audit);
138	
139	        log.info("Notification {} acknowledged by user {} from {} (session {})",
140	                notificationId, recipientId, ipAddress, sessionId);
141	        return NotificationResponse.from(n);
142	    }
143	
144	    // ── Template-based sending ─────────────────────────────────────────────────
145	
146	    /**
147	     * Renders a template and sends the resulting notification to one or more recipients.
148	     *
149	     * @param templateKey   key of an active template in the database
150	     * @param recipientIds  one or more target users
151	     * @param variables     substitution map for {@code {{placeholder}}} tokens
152	     * @param priorityOverride if non-null, overrides the template's default priority
153	     * @param relatedEntityType optional related entity type (loose coupling)
154	     * @param relatedEntityId   optional related entity ID
155	     */
156	    @Transactional
157	    public List<Notification> sendFromTemplate(String templateKey,
158	                                               List<UUID> recipientIds,
159	                                               Map<String, String> variables,
160	                                               NotificationPriority priorityOverride,
161	                                               String relatedEntityType,
162	                                               UUID relatedEntityId) {
163	        NotificationTemplate template = templateRepo.findByTemplateKeyAndActiveTrue(templateKey)
164	                .orElseThrow(() -> new IllegalArgumentException(
165	                        "No active template found for key: " + templateKey));
166	
167	        String title = template.renderTitle(variables);
168	        String body  = template.renderBody(variables);
169	        NotificationPriority priority = priorityOverride != null
170	                ? priorityOverride : template.getDefaultPriority();
171	
172	        return recipientIds.stream().map(recipientId -> {
173	            User recipient = userService.findById(recipientId);
174	            Notification n = new Notification();
175	            n.setRecipient(recipient);
176	            n.setTitle(title);
177	            n.setBody(body);
178	            n.setType(NotificationType.INFO);
179	            n.setPriority(priority);
180	            n.setCategory(template.getCategory());
181	            n.setRequiresAcknowledgment(template.isRequiresAcknowledgment());
182	            n.setTemplateKey(template.getTemplateKey());
183	            n.setVariables(variables);
184	            n.setRelatedEntityType(relatedEntityType);
185	            n.setRelatedEntityId(relatedEntityId);
186	            return notifRepo.save(n);
187	        }).toList();
188	    }
189	
190	    /**
191	     * Convenience overload for sending to a single recipient without a related entity.
192	     */
193	    @Transactional
194	    public Notification sendFromTemplate(String templateKey, UUID recipientId,
195	                                         Map<String, String> variables) {
196	        return sendFromTemplate(templateKey, List.of(recipientId), variables, null, null, null)
197	                .getFirst();
198	    }
199	
200	    // ── Ad-hoc sending (backwards-compatible) ─────────────────────────────────
201	
202	    /**
203	     * Sends a plain notification without a template.  Retained for use by other
204	     * services that compose their own title/body.
205	     */
206	    @Transactional
207	    public Notification send(UUID recipientId, String title, String body,
208	                             NotificationType type) {
209	        User recipient = userService.findById(recipientId);
210	        Notification n = new Notification();
211	        n.setRecipient(recipient);
212	        n.setTitle(title);
213	        n.setBody(body);
214	        n.setType(type);
215	        return notifRepo.save(n);
216	    }
217	
218	    @Transactional
219	    public Notification send(UUID recipientId, String title, String body,
220	                             NotificationType type,
221	                             String relatedEntityType, UUID relatedEntityId) {
222	        Notification n = send(recipientId, title, body, type);
223	        n.setRelatedEntityType(relatedEntityType);
224	        n.setRelatedEntityId(relatedEntityId);
225	        return notifRepo.save(n);
226	    }
227	
228	    // ── Templates (staff view) ─────────────────────────────────────────────────
229	
230	    public List<TemplateResponse> listTemplates() {
231	        return templateRepo.findByActiveTrueOrderByCategoryAscTemplateKeyAsc()
232	                .stream().map(TemplateResponse::from).toList();
233	    }
234	}
