3	import com.fasterxml.jackson.core.JsonProcessingException;
4	import com.fasterxml.jackson.core.type.TypeReference;
5	import com.fasterxml.jackson.databind.ObjectMapper;
6	import jakarta.persistence.AttributeConverter;
7	import jakarta.persistence.Converter;
8	
9	import java.util.Map;
10	
11	/**
12	 * JPA converter that serialises a {@code Map<String,String>} to/from a JSON
13	 * TEXT column.  Used to store notification template variable values alongside
14	 * the rendered notification text.
15	 */
16	@Converter
17	public class StringMapConverter implements AttributeConverter<Map<String, String>, String> {
18	
19	    private static final ObjectMapper MAPPER = new ObjectMapper();
20	    private static final TypeReference<Map<String, String>> MAP_TYPE = new TypeReference<>() {};
21	
22	    @Override
23	    public String convertToDatabaseColumn(Map<String, String> map) {
24	        if (map == null || map.isEmpty()) return null;
25	        try {
26	            return MAPPER.writeValueAsString(map);
27	        } catch (JsonProcessingException e) {
28	            throw new IllegalStateException("Cannot serialise notification variables to JSON", e);
29	        }
30	    }
31	
32	    @Override
33	    public Map<String, String> convertToEntityAttribute(String json) {
34	        if (json == null || json.isBlank()) return Map.of();
35	        try {
36	            return MAPPER.readValue(json, MAP_TYPE);
37	        } catch (JsonProcessingException e) {
38	            return Map.of(); // tolerate stale or malformed data
39	        }
40	    }
41	}
