19	/**
20	 * REST endpoints for the notification centre.
21	 *
22	 * <pre>
23	 * GET  /api/notifications                 — inbox (params: unreadOnly, category, page, size)
24	 * GET  /api/notifications/count           — { unread, pendingAcknowledgment }
25	 * GET  /api/notifications/{id}            — single notification
26	 * POST /api/notifications/{id}/read       — mark one as read
27	 * POST /api/notifications/read-all        — mark all as read
28	 * POST /api/notifications/{id}/acknowledge — record acknowledgment + audit
29	 *
30	 * GET  /api/notifications/templates       — list active templates (staff+)
31	 * POST /api/notifications/send            — send via template  (staff+)
32	 * </pre>
33	 *
34	 * <p>All write endpoints are authenticated.  Template listing and sending
35	 * are restricted to staff roles via {@code @PreAuthorize}.
36	 */
37	@RestController
38	@RequestMapping("/api/notifications")
39	public class NotificationController {
40	
41	    private static final String STAFF_ROLES =
42	            "hasAnyRole('ADMIN','HOUSING_ADMINISTRATOR','DIRECTOR'," +
43	            "'RESIDENT_DIRECTOR','RESIDENT_ASSISTANT','RESIDENCE_STAFF','STAFF')";
44	
45	    private final NotificationService notificationService;
46	
