49	    }
50	
51	    // ── Inbox ──────────────────────────────────────────────────────────────────
52	
53	    @GetMapping
54	    public Page<NotificationResponse> inbox(
55	            @RequestParam(defaultValue = "false") boolean unreadOnly,
56	            @RequestParam(required = false) String category,
57	            @RequestParam(defaultValue = "0")  int page,
58	            @RequestParam(defaultValue = "20") int size,
59	            @AuthenticationPrincipal ReslifeUserDetails principal) {
60	
61	        NotificationCategory cat = null;
62	        if (category != null && !category.isBlank()) {
63	            try { cat = NotificationCategory.valueOf(category.toUpperCase()); }
64	            catch (IllegalArgumentException ignored) {}
65	        }
66	
67	        Pageable pageable = PageRequest.of(page, Math.min(size, 100));
68	        return notificationService
69	                .findInbox(principal.getUserId(), unreadOnly, cat, pageable)
70	                .map(NotificationResponse::from);
71	    }
72	
73	    // ── Counts for badge display ───────────────────────────────────────────────
