135	    // ── Send via template (staff only) ────────────────────────────────────────
136	
137	    @PostMapping("/send")
138	    @PreAuthorize(STAFF_ROLES)
139	    @ResponseStatus(HttpStatus.CREATED)
140	    public Map<String, Integer> send(
